@api_view(['POST'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2)) 
def getCertificate(request):
    elementos = request.data
    if elementos == 0:
        return Response({'error': 'Bad request'})

    for item in elementos['elementos']:
        poliza_number = item['Número de Póliza']
        certificado = item['Certificado (SAAM)']
        id_categoria = item['ID Categoria SAAM']
        identificador = item['Identificador']

        caratula = Polizas.objects.filter(poliza_number = poliza_number, document_type = 3, status__in = [14, 10, 13, 12, 15], org_name = request.GET.get('org'))
        if caratula.exists():
            caratula = caratula.first()
            try:
                categoria = Polizas.objects.get(id = id_categoria)
                certificado = Polizas.objects.filter(document_type = 6, parent = categoria, certificate_number = certificado )
                if certificado.exists():
                    certificado = certificado.first()
                    item['cert'] = certificado.id
                else:
                    item['cert'] = 0
            except Exception as e:
                item['cert'] = 0
        else:
            item['cert'] = 0
    return Response(elementos)
    



