@api_view(['POST'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2)) 
def validatePolizasToCancel(request):
    elementos = request.data
    if elementos == 0:
        return Response({'error': 'Bad request'})

    for item in elementos['elementos']:

        item['found'] = False
        item['error'] = False
        item['multiple'] = False

        inicio_vig_poliza = item['INICIO_VIG_POLIZA'] if 'INICIO_VIG_POLIZA' in item else 0
        if item['CANCELAR_NOTASCREDITOPENDIENTES'] == 1 or item['CANCELAR_NOTASCREDITOPENDIENTES'] == '1':
            item['cancelnotas'] = True
        else:
            item['cancelnotas'] = False

        numero_poliza = item['POLIZA'] if 'POLIZA' in item else 0
        id_poliza = item['ID_SAAM'] if 'ID_SAAM' in item else 0

        try:
            if not id_poliza:
                inicio_vig_poliza = datetime.strptime(inicio_vig_poliza, '%d/%m/%Y')
        except Exception as e:
            print('Error on init_date', str(e))
            item['ID'] = 0
            item['error'] = True
            continue
        
        poliza = None
        item['ID'] = 0

        if id_poliza:
            poliza = Polizas.objects.filter(id = id_poliza, org_name = request.GET.get('org'))
            if poliza.exists():
                poliza = poliza.first()
                item['ID_SAAM'] = poliza.id
                item['ID'] = poliza.id
                item['found'] = True
                continue
        else:
            try:
                day = inicio_vig_poliza.day
                month = inicio_vig_poliza.month
                year = inicio_vig_poliza.year
                poliza = Polizas.objects.get(
                    org_name = request.GET.get('org'),
                    poliza_number = numero_poliza,
                    start_of_validity__day =  day,
                    start_of_validity__month =  month,
                    start_of_validity__year =  year
                )
            except Polizas.DoesNotExist:
                item['error'] = True
                continue
            except Polizas.MultipleObjectsReturned: 
                poliza = Polizas.objects.filter(
                    org_name = request.GET.get('org'),
                    poliza_number = numero_poliza,
                    start_of_validity__day =  day,
                    start_of_validity__month =  month,
                    start_of_validity__year =  year
                ).exclude(status__in =[0,11])
                if poliza.count() > 1:
                    item['error'] = True
                    item['multiple'] = True
                    continue
                else:
                    poliza = poliza.first()


            if poliza:
                item['ID'] = poliza.id
                item['ID_SAAM'] = poliza.id
                item['error'] = False
                item['found'] = True

    return Response(elementos)




@api_view(['POST'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2)) 
def cancelarPolizasPorLaoyout(request):
    elementos = request.data
    if elementos == 0:
        return Response({'error': 'Bad request'})

    for item in elementos['elementos']:

        id_poliza = item['ID_SAAM'] if 'ID_SAAM' in item else 0
        fecha_cancelacion = item['FECHA_DE_CANCELACION'] if 'FECHA_DE_CANCELACION' in item else 0
        motivo_cancelacion = item['MOTIVO'] if 'MOTIVO' in item else ''
        cancelnotas = item['cancelnotas'] if 'cancelnotas' in item else False

        try:
            fecha_cancelacion = datetime.strptime(fecha_cancelacion, '%d/%m/%Y')
        except:
            fecha_cancelacion = datetime.now()

        if id_poliza:
            poliza = Polizas.objects.filter(id = id_poliza, org_name = request.GET.get('org'))
            if poliza.exists():
                poliza = poliza.first()
                poliza.status = 11
                poliza.date_cancel = fecha_cancelacion
                poliza.reason_cancel = motivo_cancelacion
                poliza.cancelnotas = cancelnotas
                poliza.save()

                Log.objects.create(
                    model = 1,
                    event = 4,
                    identifier = 'canceló la póliza de forma definitiva.',
                    user= request.user,
                    associated_id = poliza.id,
                    org_name = request.GET.get('org')
                )
                if cancelnotas:
                    Recibos.objects.filter(
                        poliza = poliza,
                        org_name = request.GET.get('org'),
                        status = 4,
                        receipt_type = 3
                    ).update(
                        status = 2
                    )
                Recibos.objects.filter(
                    poliza = poliza,
                    org_name = request.GET.get('org'),
                    status = 4,
                    receipt_type__in = [1,2]
                ).update(
                    status = 2
                )





    return Response(elementos)



