@api_view(['POST'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2)) 
def getPolizaCaratula(request):
    elementos = request.data
    if elementos == 0:
        return Response({'error': 'Bad request'})

    for item in elementos['elementos']:
        poliza_number = item['Número de Póliza']#Caratula
        polizacaratula = item['Certificado (SAAM)']#Poliza_caratula numero
        # id_categoria = item['ID Categoria SAAM']
        # identificador = item['Identificador']

        caratula = Polizas.objects.filter(poliza_number = poliza_number, document_type = 11, status__in = [10,14], org_name = request.GET.get('org'))
        if caratula.exists():
            caratula = caratula.first()
            try:
                polizacaratula = Polizas.objects.filter(document_type = 12, poliza_number = polizacaratula, parent = caratula)
                if polizacaratula.exists():
                    polizacaratula = polizacaratula.first()
                    item['polizacaratula'] = polizacaratula.id
                else:
                    item['polizacaratula'] = 0
            except Exception as e:
                item['polizacaratula'] = 0
        else:
            item['polizacaratula'] = 0
    return Response(elementos)

@api_view(['POST'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2)) 
def getReceiptsToUpFiles(request):
    elements = request.data
    if elements == 0:
        return Response({'error': 'Bad request'})

    for item in elements['elements']:
        id_receipt = item['ID_RECIBO']#ID recibo
        policynumber = item['POLIZA']#Póliza Número
        endorsement = item['ENDOSO']
        vig_policy = item['INICIO_VIGENCIA_POLIZA']
        serie = item['SERIE_RECIBO']
        fileToUp = item['NOMBRE_ARCHIVO']
        print('---',id_receipt,policynumber,endorsement,vig_policy,serie)
        if id_receipt:
            if Recibos.objects.get(pk = int(id_receipt), org_name = request.GET.get('org'), recibo_numero = int(serie)).exists():
                receiptToUpFile = Recibos.objects.get(pk = int(id_receipt), org_name = request.GET.get('org'), recibo_numero = int(serie))
                item['receiptToUpFile'] = receiptToUpFile.id
            else:
                item['receiptToUpFile'] = 0
        else:
            p = Polizas.objects.filter(poliza_number = policynumber, document_type = [1,3, 12], start_of_validity = vig_policy,org_name = request.GET.get('org'))
            if p.exists():
                polizap = p.first()
                try:
                    if polizap.exists():
                        if endorsement:
                            endoso = Endorsement.objects.filter(number_endorsement = endorsement, org_name = request.GET.get('org'))
                            if endoso.exists():
                                endoso = endoso.first()
                                receiptToUpFile = Recibos.objects.get(policy = p, endorsement = endoso, receipt_type = 2, org_name = request.GET.get('org'), recibo_numero = int(serie))
                                if receiptToUpFile.exists():
                                    item['receiptToUpFile'] = receiptToUpFile.id
                                else:
                                    item['receiptToUpFile'] = 0
                            else:
                                item['receiptToUpFile'] = 0
                        else:
                            receiptToUpFile = Recibos.objects.get(policy = p,receipt_type =1,org_name = request.GET.get('org'), recibo_numero = int(serie))
                            if receiptToUpFile.exists():
                                item['receiptToUpFile'] = receiptToUpFile.id
                            else:
                                item['receiptToUpFile'] = 0
                    else:
                        item['receiptToUpFile'] = 0
                except Exception as e:
                    item['receiptToUpFile'] = 0
            else:
                item['receiptToUpFile'] = 0
    return Response(elements)



@api_view(['POST'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2)) 
def DeleteColectivity(request):
    identifier = request.data['id']
    try:
        logs = request.data['logs']
    except Exception as er:
        logs = ''
    try:
        poliza = Polizas.objects.get(pk = int(identifier))
    except Polizas.DoesNotExist:
        return Response(status.HTTP_404_NOT_FOUND)
    
    if not poliza.poliza_number:
        poliza.poliza_number = poliza.internal_number if poliza.internal_number else identifier
    enviar = True
    if logs:
        log_data= send_log_complete(request.user,  request.GET.get('org'), 'DELETE', 1, 'elimino la Póliza de Grupo: '+poliza.poliza_number if poliza.poliza_number else poliza.internal_number, {},logs, request.data['id'])
        enviar = False
    if poliza.poliza_number:
        if enviar:
            send_log(request.user, request.GET.get('org'), 'DELETE', 1, 'elimino la Póliza de Grupo: '+poliza.poliza_number if poliza.poliza_number else poliza.internal_number, request.data['id'])
        childs = Polizas.objects.filter(caratula = poliza.id)
        for child in childs:
            child.status = 0
            child.save()
        poliza.status = 0
        poliza.save()
        return Response(status.HTTP_200_OK)
    else:
        return Response(status.HTTP_400_BAD_REQUEST)

@api_view(['POST'])
@permission_classes([IsAuthenticatedV2, IsOrgMemberV2]) 
def DeletePolicies(request):
    identifier = request.data['id']
    try:
        poliza = Polizas.objects.get(pk = int(identifier))
    except Polizas.DoesNotExist:
        return Response(status.HTTP_404_NOT_FOUND)


    if send_log(request.user, request.GET.get('org'), 'DELETE', 1, poliza.poliza_number, request.data['id']):
        poliza.delete()
    else:
        return Response(status.HTTP_400_BAD_REQUEST)

    return Response(status.HTTP_200_OK)

class HistoricoPolicyViewSet(viewsets.ModelViewSet):
    serializer_class = HistoricoPolicySerializer
    permission_classes = (IsAuthenticatedV2, IsOrgMemberV2)


    def get_queryset(self):
        try:
            parent = (self.request.GET.get('actual_id'))
            renew_filters = [Q(base_policy = parent), 
                            Q(new_policy = parent)]
            coincidences = OldPolicies.objects.filter(reduce(OR, renew_filters), org_name = self.request.GET.get('org'))
            coincidences = coincidences.exclude(base_policy__status = 0).exclude(new_policy__status = 0)
            return coincidences
        except:
            return []

class GetRenovation(viewsets.ModelViewSet):
    serializer_class = HistoricoPolicySerializer
    permission_classes = (IsAuthenticatedV2, IsOrgMemberV2 )


    def get_queryset(self):
        parent = (self.request.GET.get('actual_id'))
        coincidences = OldPolicies.objects.filter(new_policy = parent, org_name = self.request.GET.get('org'))

        return coincidences

class RenovationViewSet(viewsets.ModelViewSet):
    serializer_class = PolizaRenoSerializer
    permission_classes = (IsAuthenticatedV2, IsOrgMemberV2)
    def partial_update(self, request, pk=None):      
        try:    
            if request.data['status'] == '0' or  request.data['status'] == 0:
                queryset = Polizas.objects.all()
                cf = get_object_or_404(queryset, pk=pk)
                if (delete_ots(request) and cf.status <= 2) or (delete_policies(request) and cf.status > 2):
                    serializer = PolizaRenoSerializer(cf, context={'request': request}, data=request.data, partial=True)
                    serializer.is_valid(raise_exception=True)
                    serializer.save()
                    return Response(serializer.data)                           
                
                else:
                    raise PermissionDenied('No tienes acceso a esta función') 

            elif request.data['status'] == '11' or  request.data['status'] == 11 or  request.data['status'] == 2 or  request.data['status'] == '11' or  request.data['status'] == 4 or  request.data['status'] == '4':
                queryset = Polizas.objects.all()
                cf = get_object_or_404(queryset, pk=pk)
                if (cancel_ots(request) and cf.status <= 2) or  (cancel_policies(request) and cf.status > 2):
                    serializer = PolizaRenoSerializer(cf, context={'request': request}, data=request.data, partial=True)
                    serializer.is_valid(raise_exception=True)
                    serializer.save()
                    return Response(serializer.data)                           
                
                else:
                    raise PermissionDenied('No tienes acceso a esta función') 
            else:
                queryset = Polizas.objects.all()
                cf = get_object_or_404(queryset, pk=pk)

                if (admin_ots(request) and cf.status <= 2) or  (admin_polizas(request) and cf.status > 2):
                    serializer = PolizaRenoSerializer(cf, context={'request': request}, data=request.data, partial=True)
                    serializer.is_valid(raise_exception=True)
                    serializer.save()
                    return Response(serializer.data)
                else:
                    raise PermissionDenied('No tienes acceso a esta función')             
        except:
            queryset = Polizas.objects.all()
            cf = get_object_or_404(queryset, pk=pk)
            if (admin_ots(request) and cf.status <= 2) or  (admin_polizas(request) and cf.status > 2):
                try:
                    if 'documento_pago' in request.data.keys() and 'fecha_de_pago' in request.data.keys() and 'forma_pago' in request.data.keys() and 'cantidad' in request.data.keys() and request.data['documento_pago'] and request.data['fecha_de_pago'] and request.data['forma_pago'] and request.data['cantidad'] and cf.document_type == 6: 
                        caratula = Polizas.objects.get(pk = cf.caratula)
                        recibo_1 = Recibos.objects.filter(poliza = caratula , status = 4).order_by('recibo_numero')
                        recibo_2 = Recibos.objects.filter(poliza = cf.parent.parent , status = 4).order_by('recibo_numero')
                        recibo = recibo_1 | recibo_2
                        recibo = recibo.first()
                        pagos = Pagos.objects.filter(recibo = recibo).aggregate(Sum('pago'))['pago__sum']
                        if pagos:
                            if float(recibo.prima_total) < (float(pagos) + float(request.data['cantidad'])): 
                                raise APIException(500)
                        else:
                            if float(recibo.prima_total) < (float(request.data['cantidad'])): 
                                raise APIException(500)
                        certificados_a_pagar = request.data['certificados_a_pagar']
                        for c in certificados_a_pagar:
                            p = Polizas.objects.get(id=c)
                            p.save()                            
                        
                        Pagos.objects.create(
                            owner = recibo.owner,
                            org_name = recibo.org_name,
                            recibo = recibo,
                            pago = request.data['cantidad'],
                            fecha_de_pago = request.data['fecha_de_pago'],
                            forma_pago = request.data['forma_pago'],
                            documento_pago = request.data['documento_pago']
                        )
                        pagos = Pagos.objects.filter(recibo = recibo).aggregate(Sum('pago'))['pago__sum']
                        if float(recibo.prima_total) == float(pagos):
                            recibo.status = 1
                            recibo.save()
                except Exception as e:
                    raise APIException('La cantidad de pagos superan la prima total del recibo o la cantidad ingresada es incorrecta')
                    
                serializer = PolizaRenoSerializer(cf, context={'request': request}, data=request.data, partial=True)
                serializer.is_valid(raise_exception=True)
                serializer.save()
                return Response(serializer.data)
    
            else:
                raise PermissionDenied('No tienes acceso a esta función')
                
    def perform_create(self, serializer):
        try:
            obj =serializer.save(owner=self.request.user, org_name = self.request.GET.get('org'))
        except:
            obj =serializer.save(owner=self.request.user, org_name=self.request.POST.get('org'))
        try:
            if obj.document_type in [1,3,12]:
                configuracion = OrgInfo.objects.filter(org_name = obj.org_name)[0]
                if configuracion.renovacion and permisoCorreosElectronicos(self, self.request):
                    #enviar recordatorio OT
                    if obj.contractor.email:
                        data = {
                            'model':9,
                            'id':obj.id,
                            'org':obj.org_name
                        }
                        sendEmailAutomatico(self, self.request,data)
        except Exception as m:
            print('erorr email atm---',m) 
        # if obj.id:
        #     send_log(self.request.user, get_org(self.request.GET.get('org')), 'POST', 1, obj.poliza_number, obj.id)

    def get_queryset(self):
        return custom_get_queryset(self.request, Polizas)


