class PolizasViewSet(viewsets.ModelViewSet):
    serializer_class = PolizaHyperSerializer
    permission_classes = (IsAuthenticatedV2, IsOrgMemberV2)

    def get_id_from_url_api(self, url_api):
        split_url = url_api.split('/')
        return split_url[-2]

    def convert_type(self, value, type_to_convert, is_date):
        if value == 'None' or value == None:
            return ''
        
        if is_date == True:
            value = str(value).replace('.000Z', '').replace('+00:00', '').replace('T', ' ')

        try:
            value = type_to_convert(value)
        except Exception as e:
            pass
        return value

    def identifica_atributos_actualizados(self,request, pk=None, registrado=False):
        atributos_actualizados = ''
        atributos_originales = ''
        poliza_data_request = {}
        poliza_data_in_db = {}        
        poliza = Polizas.objects.get(pk=pk)
        for key, value in request.data.items():
            if key == 'emision_date' or key == 'old_policies':
                continue

            value = str(value)
            value_request = value
            if 'http' in value:
                value_request = self.get_id_from_url_api(value)
            try:
                value_in_db = eval("poliza.%s.pk" % key)
            except Exception as e:
                value_in_db = eval("poliza.%s" % key)

            is_date = False
            if key == 'start_of_validity' or key == 'end_of_validity':
                is_date = True
            if key =='ref_policy':
                getRef=ReferenciadoresInvolved.objects.filter(policy=poliza,org_name = poliza.org_name).values_list('referenciador',flat=True)
                #asignar referenciadores padre a sus polizas hijo 
                try:
                    ids_refcol = []
                    for rf in request.data['ref_policy']:
                        valid=self.get_id_from_url_api(rf['referenciador'])
                        if int(valid) in getRef:
                            ids_refcol.append(valid)
                        else:
                            ids_refcol.append(valid)
                            userf=User.objects.get(pk=int(valid))
                            mensaje=' añadio un referenciador a la póliza '+str(userf.first_name)+' '+str(userf.last_name)
                            # send_log(self.request.user,poliza.org_name, 'PATCH', 18, mensaje, poliza.pk)
                    conteod=ReferenciadoresInvolved.objects.filter(policy = poliza,org_name = poliza.org_name).exclude(referenciador__in=ids_refcol)
                    if len(conteod) >0:
                        mensaje=' elimino '+str(len(conteod))+' referenciadores de la póliza'
                        # send_log(self.request.user,poliza.org_name, 'PATCH', 18, mensaje, poliza.pk)
                        ReferenciadoresInvolved.objects.filter(policy = poliza,org_name = poliza.org_name).exclude(referenciador__in=ids_refcol).delete()
                except Exception as ty:
                    print('-error fl refs-',ty)
            value_request = self.convert_type(value_request, float, is_date)
            value_in_db = self.convert_type(value_in_db, float, is_date)
            if is_date:
                try:
                    fecha_req=parser.parse(value_request)
                    fecha_db=parser.parse(value_in_db)
                    if fecha_req.date() != fecha_db.date():
                        value_request = self.convert_type(value_request, int, is_date)
                        value_request = self.convert_type(value_request, str, is_date)
                        atributos_actualizados += key + ', '
                        atributos_originales += key + ', '   
                except:
                    if value_request != value_in_db:
                        value_request = self.convert_type(value_request, int, is_date)
                        value_request = self.convert_type(value_request, str, is_date)
                        atributos_actualizados += key + ', '
                        atributos_originales += key + ', '             
            else:
                if value_request != value_in_db:
                    value_request = self.convert_type(value_request, int, is_date)
                    value_request = self.convert_type(value_request, str, is_date)

                    # atributos_actualizados += key + ' (a ' + value_request +  '), '
                    # atributos_originales += key + ' (a ' + str(value_in_db) +  '), '
                    atributos_actualizados += key + ', '
                    atributos_originales += key + ', '

        cambio_nombre_atributos = [
            ('end_of_validity', 'Fin de vigencia'),
            ('observations', 'Observaciones'),
            ('poliza_number', 'Número de poliza'),
            ('start_of_validity', 'Inicio de vigencia'),
            ('address', 'Domicilio'),
            ('business_line', 'Línea de Negocio'),
            ('f_currency', 'Moneda'),
            ('identifier', 'identificador'),
            ('p_total', 'Prima total'),
            ('p_neta', 'Prima neta'),
            ('is_renewable', 'Es renovada'),
            ('contractor', 'Contratante'),
            ('policy_type', 'Tipo'),
            ('reason_ren', 'Razón renovación'),
            ('reason_cancel', 'Razón Cancelación'),
            ('renewed_status', 'Estatus Renovación'),
            ('status', 'Estatus'),
            ('folio', 'Folio'),
            ('ref_policy', 'Referenciador(es)'),
            ('collection_executive', 'Ejecutivo Cobranza'),
            ('internal_number', 'Folio Interno'),
            ('forma_de_pago', 'Forma Pago'),
            ('business_line', 'Línea de Negocio'),
            ('address', 'Dirección'),
            ('date_cancel', 'Fecha de Cancelación'),
            ('emision_date', 'Fecha de Emisión'),
            ('observations', 'Observaciones'),
            ('reason_cancel', 'Razón de Cancelación'),
            ('reason_rehabilitate', 'Razón de Rehabilitación'),
            ('reason_ren', 'Razón de NO Renovación')
        ]

        if atributos_actualizados != '':
            for key, value in cambio_nombre_atributos:
                atributos_actualizados = atributos_actualizados.replace(key, value)

        if atributos_originales != '':
            for key, value in cambio_nombre_atributos:
                atributos_originales = atributos_originales.replace(key, value)

            mensaje = 'actualizó los atributos: ' + atributos_actualizados[:-2]
            mensajeOriginal = 'datos originales: ' + atributos_originales[:-2]
            mensajeCambio = 'actualizó los atributos: ' + atributos_actualizados[:-2]
            if poliza.document_type == 1 or poliza.document_type==12:
                # send_log(self.request.user, request.GET.get('org'), 'PATCH', 1, mensaje, poliza.pk)
                send_log_complete(self.request.user, request.GET.get('org'), 'PATCH', 1, mensaje, mensajeOriginal,mensajeCambio, poliza.pk)
            if poliza.document_type == 11:
                if registrado==False:
                    registrado=True
                    # send_log(self.request.user, request.GET.get('org'), 'PATCH', 1, mensaje, poliza.pk)
                    send_log_complete(self.request.user, request.GET.get('org'), 'PATCH', 18, mensaje, mensajeOriginal,mensajeCambio, poliza.pk)
