@api_view(['POST'])
@pm((IsAuthenticatedV2, ))
def GetPolizasColectividad(request):  
    org_name = request.GET.get('org')
    caratula = Polizas.objects.get(pk = int(request.data['caratula']), org_name = org_name, document_type = 11)  
    polizas = Polizas.objects.filter(parent = caratula.id, org_name = org_name, document_type = 12, status__in = [13,14])   
    pols = PolizaCaratulaResumeInfoSerializer(polizas, context = {'request':request}, many = True)
    return Response({'data': pols.data})


