def CertificadosCaratulaViewSet(request):  
    org_name = request.GET.get('org')
    caratula = Polizas.objects.get(pk = int(request.GET.get('caratula')), org_name = org_name, document_type = 11)  
    polizas = Polizas.objects.filter(parent = caratula.id, org_name = org_name, document_type = 12)   
    paginator = Paginator(polizas, 10)
    try:
        page = request.GET.get('page')
        results = paginator.page(page)
    except:
        results = paginator.page(1)
    serializer = PolizaCaratulaResumeInfoSerializer(results, context = {'request':request}, many = True)
    return JsonResponse({'results': serializer.data, 'count': len(polizas)})

