def permisoCorreosElectronicos(self, request):
    message = 'No tienes acceso a esta función'
    if request.method == 'PATCH' or request.method == 'PUT' or request.method == 'POST' or request.method == 'DELETE' or request.method == 'GET':
        token  = request.META['HTTP_AUTHORIZATION'].replace('Bearer ', '')
        session_obj = Session.objects.get(jwt_token=token)
        permissions = session_obj.permissions['SAAM']
        for permission in permissions['Correos electronicos']:
            if (permission['name']=="Correos" and permission['checked']):
                return True
    return False 
