@api_view(['POST'])
@pm((IsAuthenticatedV2, ))
def EndosoCertificadoRelationSet(request):  
    certificate =  int(request.data['certificate'])
    cert = Polizas.objects.get(id = int(certificate), org_name = request.GET.get('org'))
    endorsement =  int(request.data['endoso'])
    endoso = Endorsement.objects.get(id = int(endorsement), org_name = request.GET.get('org'))
    relation = EndorsementCert(
        certificate = cert,
        endorsement = endoso
        )
    relation.save()     
    if relation.id:
        send_log(request.user, request.GET.get('org'), 'POST', 10, 'creo certificados al endoso ', relation.id)
    endCert = EndorsementCertsSerializer(relation, context = {'request':request}, many = False)
    return Response({'data': endCert.data})

class CreateMassiveCertificates(viewsets.ModelViewSet):
    serializer_class = PolizaSerializer
    permission_classes = (IsAuthenticatedV2, IsOrgMemberV2)

    def create(self, request, *args, **kwargs):
        serializer = self.get_serializer(data = request.data, many = isinstance(request.data,list))
        serializer.is_valid(raise_exception=True)
        obj = serializer.save(owner=self.request.user, org_name = self.request.GET.get('org'))
        headers = self.get_success_headers(serializer.data)
        return Response(serializer.data, status=status.HTTP_201_CREATED, headers=headers)

    def get_queryset(self):
        return custom_get_queryset(self.request, Polizas)

@api_view(['POST'])
@pm((IsAuthenticatedV2, ))
def massiveUpdateCertsInfoAdicional(request):
    data = request.data
    org_name = request.GET['org']
    ok = 'Error al actualizar'
    subramo_code = request.data[0]['subramo']

    try:
        for a in request.data:
            if subramo_code == 9:#Autos
                try:
                    docType = a['document_type']
                    caratula = a['caratula']
                    certNumber = a['certificate_number']
                    autoDamages = a['automobiles_policy'][0]
                    try:
                        certificado = Polizas.objects.get(document_type = docType, caratula = caratula, certificate_number = certNumber, org_name = request.GET.get('org'))
                        if certificado:
                            cSerializar = PolizaHyperSerializer(certificado, context={'request': request}, many = False)
                            id_auto = cSerializar.data['automobiles_policy'][0]['id']
                            autos = AutomobilesDamages.objects.get(id = id_auto)                       
                            autos.adjustment = autoDamages['adjustment']
                            autos.beneficiary_address = autoDamages['beneficiary_address']
                            autos.preferential_benefiaciary = autoDamages['preferential_benefiaciary']
                            autos.beneficiary_rfc = autoDamages['beneficiary_rfc']
                            autos.charge_type = autoDamages['charge_type'] if autoDamages['charge_type'] else 0
                            autos.mont_adjustment = autoDamages['mont_adjustment'] if autoDamages['mont_adjustment'] else 0
                            autos.mont_special_team = autoDamages['mont_special_team'] if autoDamages['mont_special_team'] else 0
                            autos.special_team = autoDamages['special_team']
                            autos.procedencia = autoDamages['procedencia'] if autoDamages['procedencia'] else 0
                            autos.service = autoDamages['service']
                            autos.sum_insured = autoDamages['sum_insured'] if autoDamages['sum_insured'] else 0
                            autos.email = autoDamages['email']                        
                            try:
                                autos.save()
                                ok = 'Actualizados'
                            except Exception as rer:
                                return JsonResponse({'status': 'Error al actualizar'}) 
                    except Exception as e:
                        return JsonResponse({'status': 'Error al actualizar'}) 
                except Exception as e:
                    return JsonResponse({'status': 'Error al actualizar'}) 
            elif subramo_code == 3 or subramo_code == 4 or subramo_code == 2:#GM,S,AP
                try:
                    docType = a['document_type']
                    caratula = a['caratula']
                    certNumber = a['certificate_number']
                    gmCertificate = a['accidents_policy'][0]
                    try:
                        certificado = Polizas.objects.get(document_type = docType, caratula = caratula, certificate_number = certNumber, org_name = request.GET.get('org'))
                        if certificado:
                            cSerializar = PolizaHyperSerializer(certificado, context={'request': request}, many = False)
                            id_gm = cSerializar.data['accidents_policy'][0]['id']
                            gm_cert = AccidentsDiseases.objects.get(id = id_gm)  
                            gm_pers = Personal_Information.objects.get(id = gm_cert.personal.id)
                            gm_pers.email = gmCertificate['email'] if gmCertificate['email'] else ''
                            try:
                                gm_pers.save()
                                ok = 'Certificados Actualizados'
                            except Exception as rer:
                                return JsonResponse({'status': 'Error al actualizar (GM)'}) 
                    except Exception as e:
                        return JsonResponse({'status': 'Error al actualizar (GM)'}) 
                except Exception as e: 
                    return JsonResponse({'status': 'Error al actualizar (GM)'}) 
            elif subramo_code == 1:#Vida
                try:
                    docType = a['document_type']
                    caratula = a['caratula']
                    certNumber = a['certificate_number']
                    vidaCertificate = a['life_policy'][0]
                    try:
                        certificado = Polizas.objects.get(document_type = docType, caratula = caratula, certificate_number = certNumber, org_name = request.GET.get('org'))
                        if certificado:
                            cSerializar = PolizaHyperSerializer(certificado, context={'request': request}, many = False)
                            id_vida = cSerializar.data['life_policy'][0]['id']
                            vida_cert = Life.objects.get(id = id_vida)  
                            vida_pers = Personal_Information.objects.get(id = vida_cert.personal.id)
                            vida_pers.email = vidaCertificate['email'] if vidaCertificate['email'] else ''
                            try:
                                vida_pers.save()
                                ok = 'Certificados Actualizados'
                            except Exception as rer:
                                return JsonResponse({'status': 'Error al actualizar (VIDA)'}) 
                    except Exception as e:
                        return JsonResponse({'status': 'Error al actualizar (VIDA)'}) 
                except Exception as e:
                    return JsonResponse({'status': 'Error al actualizar (VIDA)'}) 
            else: #Danios
                return JsonResponse({'status': 'Error al actualizar (Subramo no coincide)'}) 
        return JsonResponse({'status': ok})
    except Exception as e:
        return JsonResponse({'status': 'Error sl'})

