@api_view(['POST'])
@pm((IsAuthenticatedV2, ))
def CreateMassiveBajasEndorsements(request):
    certs = []
    beneficiaries_only = []
    for a in request.data:
        try:    
            caratula = Polizas.objects.get(poliza_number = a['NUM_POLIZA'], document_type = 3, org_name = request.GET.get('org'),status__in = [10,14])
        except Polizas.DoesNotExist:
            return Response(status=status.HTTP_404_NOT_FOUND, data = 'No se encontró la póliza')
        except Polizas.MultipleObjectsReturned:
            caratula = Polizas.objects.filter(poliza_number = a['NUM_POLIZA'], document_type = 3, org_name = request.GET.get('org')).exclude(status = 0).latest('id')
        
        try:
            certificate_number = a['CERTIFICADO']
        except:
            certificate_number = a['INCISO']
        try:
            if int(a['TIPO']) == 1:
                try:
                    certificado = Polizas.objects.get(certificate_number = certificate_number, document_type = 6, caratula = caratula.id, parent_id = a['CATEGORIA'])
                    certs.append(certificado)
                except Polizas.MultipleObjectsReturned:
                    return Response(status=status.HTTP_404_NOT_FOUND, data = 'Existe más de un objeto con el mismo número de certificado')
            else:#Relación con certificado
                try:
                    certificado = Polizas.objects.get(certificate_number = certificate_number, document_type = 6, caratula = caratula.id, parent_id = a['CATEGORIA'])
                    # certs.append(certificado)
                except Polizas.MultipleObjectsReturned:
                    return Response(status=status.HTTP_404_NOT_FOUND, data = 'Existe más de un objeto con el mismo número de certificado')
        except Exception as ers:
            try:
                certificado = Polizas.objects.get(certificate_number = certificate_number, document_type = 6, caratula = caratula.id, parent_id = a['CATEGORIA'])
                certs.append(certificado)
            except Polizas.MultipleObjectsReturned:
                return Response(status=status.HTTP_404_NOT_FOUND, data = 'Existe más de un objeto con el mismo número de certificado')
        # Dependientes
        try:
            np = a['NUM_POLIZA'] + ' - INC. ' + str(a['CERT_GRAL'])
            try:
                caratula_exist = Polizas.objects.get(caratula = str(caratula.id),certificate_number = a['CERT_GRAL'], poliza_number = np, org_name = request.GET.get('org'), status__in = [10,14,1,19])
            except Exception as e:
                caratula_exist = Polizas.objects.get(caratula = str(caratula.id),certificate_number = a['CERT_GRAL'], org_name = request.GET.get('org'),status__in = [10,14,1,19])
        except Exception as rr:
            caratula_exist = None
        if caratula_exist or certificado:
            try:
                if int(a['TIPO']) == 2:
                    full_name = a['AP_PAT']+' '+a['AP_MAT']+' '+a['NOMBRE']
                    if caratula.subramo.subramo_code == 3:
                        # ac
                        accidents_policy = AccidentsDiseases.objects.filter(policy = certificado.id, org_name=org_name)
                        asegurado = accidents_policy[0].personal
                        form_= AccidentsDiseases.objects.get(policy = certificado.id, org_name =  request.GET.get('org'))                 
                        if form_:
                            try:
                                Deepndientes = Relationship.objects.get(accident = form_, is_active = True, last_name__iexact = a['AP_PAT'], second_last_name__iexact = a['AP_MAT'], first_name__iexact = a['NOMBRE'])
                                beneficiaries_only.append(Deepndientes)
                            except Relationship.MultipleObjectsReturned:
                                return Response(status=status.HTTP_404_NOT_FOUND, data = 'Existe mas de un objeto con el mismo nombre de Dependientes')
                    if caratula.subramo.subramo_code == 1:
                        # vida
                        accidents_policy = Life.objects.filter(policy = certificado.id, org_name=org_name)
                        asegurado = accidents_policy[0].personal
                        form_= Life.objects.get(policy = certificado.id, org_name =  request.GET.get('org'))                 
                        if form_:
                            try:
                                Deepndientes = Beneficiaries.objects.get(life = form_, is_active = True, last_name = a['AP_PAT'], second_last_name = a['AP_MAT'], first_name = a['NOMBRE'])
                                beneficiaries_only.append(Deepndientes)
                            except Beneficiaries.MultipleObjectsReturned:
                                return Response(status=status.HTTP_404_NOT_FOUND, data = 'Existe mas de un objeto con el mismo nombre de Beneficiario')
            except Exception as ers:
                pass
            # Bebeficiarios

        try:
            fecha_movimiento = datetime.strptime(a['FEC_MOVIMIENTO'],"%Y-%m-%dT%H:%M:%S.%fZ")
        except:
            fecha_movimiento = datetime.today()
    endoso = Endorsement(
        # endorsement_type = "B" if caratula.administration_type == 2 else "D",
        endorsement_type = "D",
        policy = caratula,
        org_name = caratula.org_name,
        owner = caratula.owner,
        init_date = fecha_movimiento, # Aqui va la fecha del movimiento,
        end_date = caratula.end_of_validity,
        policy_type = 2,
        concept = 25
        )
    endoso.save()
    endoso.internal_number = 'OTE' + '%07d' % endoso.id
    endoso.save()

    if beneficiaries_only:
        for x in beneficiaries_only:
            x.endorsement = endoso
            x.save()
    serializer = EndorsementHyperSerializer(endoso, context = {'request':request}, many = False)
    for cert in certs:
        relation = EndorsementCert(
            certificate = cert,
            endorsement = endoso
            )
        relation.save()
    return JsonResponse({'status': 'created', 'id': endoso.id, 'data': serializer.data})

