@api_view(['POST'])
@pm((IsAuthenticatedV2, ))
def activateCert(request):
    id_certificado = int(request.data['certificate'])
    certificado = Polizas.objects.filter(id = id_certificado)

    certificado = certificado[0]
    if not certificado.certificado_inciso_activo:
        certificado.certificado_inciso_activo = True
        try:
            certificado.certificate_number = request.data['certificate_number']
        except:
            pass
        certificado.save()

    if certificado.subramo.subramo_code == 1:
        form_ = Life.objects.filter(policy = certificado)
        relations = Beneficiaries.objects.filter(life = form_)
        
        for rel in relations:
            if not rel.is_active:
                rel.is_active = True
                rel.save()
    elif certificado.ramo.ramo_code == 2:
        form_ = AccidentsDiseases.objects.filter(policy = certificado)
        relations = Relationship.objects.filter(accident = form_)
        
        for rel in relations:
            if not rel.is_active:
                rel.is_active = True
                rel.save()

    serializer = PolizaMoreEditSerializer(certificado, context={'request': request}, many = False)
    return Response(serializer.data)

