@api_view(['POST'])
@pm((IsAuthenticatedV2, ))
def copyData(request):
    newp = Polizas.objects.get(pk = request.data['newp'])
    oldp = Polizas.objects.get(pk = request.data['oldp'])
    cambio = int(request.data['cambio'])
    org_name = request.GET.get('org')

    log = Log.objects.filter(model = 1, associated_id = request.data['oldp'], org_name=org_name)
    for l in log:
        l.associated_id = int(request.data['newp'])
        l.save()

    adjuntos = PolizasFile.objects.filter(owner = oldp, org_name=org_name)
    for f in adjuntos:
        f.owner = newp
        f.save()

    siniestros = Siniestros.objects.filter(poliza = oldp)
    for s in siniestros:
        s.poliza = newp
        s.save()
    
    if cambio == 1:
        recibos = Recibos.objects.filter(poliza = oldp, org_name=org_name)
        for r in recibos:
            r.poliza = newp
            r.save()

    return JsonResponse({'updated': 'completed'})

class SetCaratulaViewSet(viewsets.ModelViewSet):
    serializer_class = CreateCaratulaSerializer 
    permission_classes = (IsAuthenticatedV2, IsOrgMemberV2 )

    queryset = Polizas.objects.all()
    def perform_create(self, serializer):
        if self.request.data['vendor'] != '' and self.request.data['vendor'] != None:
            try:

                vendor = User.objects.get(id = int(self.request.data['vendor']))
            except User.DoesNotExist:
                return Response({'error':'Vendor does not exist'})
            except Exception as e:
                return Response({'error':str(e)})
        else:
            vendor = None


        org = self.request.GET.get('org')
        if org == None:
            org = self.request.POST.get('org')
        try:
            p_neta = self.request.data['p_neta']
            obj = serializer.save(owner=self.request.user, 
                org_name=org,
                p_neta = self.request.data['p_neta'],
                p_total = self.request.data['p_total'],
                descuento = self.request.data['descuento'],
                iva = self.request.data['iva'],
                derecho = self.request.data['derecho'],
                rpf = self.request.data['rpf'])
        except:
            obj = serializer.save(owner=self.request.user, org_name=org)
        
        if obj.id:
            if obj.poliza_number:
                send_log(self.request.user, self.request.GET.get('org'), 'POST', 18, 'creó la caratula', obj.id)
            else:
                send_log(self.request.user, self.request.GET.get('org'), 'POST', 18, 'creó la OT', obj.id)
