@api_view(['POST'])
@pm((IsAuthenticatedV2,))
def EvaluateMassiveCertificatesComplete(request):
    data = request.data
    org_name = request.GET.get('org')
    owner = request.user

    try:
        caratula_id = data[0].get('caratula')
        if not caratula_id:
            return JsonResponse({'data': 'Carátula ID is required'}, status=400)

        try:
            caratula = Polizas.objects.get(pk=caratula_id, document_type=3, org_name=org_name)
        except Polizas.DoesNotExist:
            return Response(status=status.HTTP_404_NOT_FOUND, data='No se encontró la Carátula')
        except Polizas.MultipleObjectsReturned:
            return Response(status=status.HTTP_404_NOT_FOUND, data='Existe más de un registro')

        if caratula.ramo.ramo_code == 3 and caratula.subramo.subramo_code == 9:
            if not any(d.get('automobiles_policy') for d in data):
                return JsonResponse({'data': 'Debe seleccionar el Layout de Flotillas'}, status=400)

        def validate_automobile_policy(policy):
            required_fields = ['serial', 'email', 'brand', 'model', 'year', 'version', 'usage']
            for field in required_fields:
                if not policy.get(field):
                    return "Debe agregar un "+str(field.capitalize())+" al Auto"
            return None

        for dat in data:
            policy_list = dat.get('automobiles_policy', [])
            if not policy_list:
                return Response(data={'exist': False}, status=status.HTTP_200_OK)

            policy = policy_list[0]
            validation_error = validate_automobile_policy(policy)
            if validation_error:
                return JsonResponse({'data': validation_error}, status=400)

            serial = policy.get('serial')
            autos = AutomobilesDamages.objects.filter(serial=serial, org_name=org_name)
            for auto in autos:
                if auto.policy.document_type in [6, 1, 12]:
                    parent = auto.policy.parent
                    grandparent = getattr(parent, 'parent', None) if parent else None
                    great_grandparent = getattr(grandparent, 'parent', None) if grandparent else None
                    parent_status = getattr(great_grandparent, 'status', None)

                    # Check the conditions for existing policies
                    if parent_status in [14, 10] or auto.policy.status in [14, 10]:
                        return Response(data={'exist': True, 'poliza': auto.policy.poliza_number}, status=status.HTTP_200_OK)

        return Response(data={'exist': False}, status=status.HTTP_200_OK)

    except Exception as e:
        print('Error:', e)
        return Response(data={'exist': False}, status=status.HTTP_200_OK)

 

