        receipt = {
            'recibo_numero': i + 1,
            'prima_neta': float((obj['prima_neta'])),
            'rpf': float((obj['rpf'])),
            'derecho': float((obj['derecho'])),
            'iva': float((obj['iva'])),
            'sub_total': float((obj['subTotal'])),
            'prima_total': float((obj['primaTotal'])),
            'comision': float((obj['comision'])),
            'receipt_type': 5,
            'delivered': False,
            'fecha_inicio': obtenerVigenciaInicialDia(i, dias_resta,inicio, fin),
            'fecha_fin': obtenerVigenciaFinalDia(dias_resta_fin,inicio, fin),
        }

        receipt['vencimiento'] = obtenerVencimiento(i, receipt['fecha_inicio'],inicio, fin);
        receipts.append(receipt)       

        dias_resta = dias_resta - fp
        dias_resta_fin = dias_resta_fin - fp
        if i == 0:
            firstReceipt['recibo_numero'] = i + 1
            firstReceipt['derecho'] = firstReceipt['derecho']
