def obtenerVigenciaInicialMes (index, value, inicio, fin):
    fin = str(fin.strftime("%d/%m/%y"))

    date_initial = (fin).split('/')
    dia = int(date_initial[0])
    mes = int(date_initial[1])
    anio = int(date_initial[2])
    if len(str(dia)) == 1:
        dia = '0'+str(dia)
    if len(str(mes)) == 1:
        mes = '0'+str(mes)
    initial_1 = str(dia)+"/"+str(mes) +"/"+str(anio)

    try:
        f = "%d/%m/%y"        
        initial_2 = datetime.strptime(initial_1 , f)
    except Exception as r:
        f = "%m/%d/%y"        
        initial_2 = datetime.strptime(initial_1 , f)
    fecha = initial_2
    fecha = difMonth(fecha, value)
    if index == 0:
        try:
            inicio = str(inicio.strftime("%d/%m/%y"))
        except Exception as re:
            inicio = inicio
        return inicio
    else:
        return str(fecha.strftime("%d/%m/%y"))
# import datetime
import dateutil.relativedelta

def difMonth(date, mes):
    d = datetime.strptime(str(date), "%Y-%m-%d %H:%M:%S")
    d2 = d - dateutil.relativedelta.relativedelta(months=int(mes))  #datetime.datetime(2013, 2, 28, 0, 0)
    return d2

def difDays(date, mes):
    d = datetime.strptime(str(date), "%Y-%m-%d %H:%M:%S")
    d2 = d - dateutil.relativedelta.relativedelta(days=int(mes))  #datetime.datetime(2013, 2, 28, 0, 0)
    return d2

def obtenerVigenciaFinalMes (value, inicio, fin):
    fin = str(fin.strftime("%d/%m/%y"))

    date_initial = (fin).split('/');
    dia = int(date_initial[0]);
    mes = int(date_initial[1]);
    anio = int(date_initial[2]);
    if len(str(dia)) == 1:
        dia = '0'+str(dia)
    if len(str(mes)) == 1:
        mes = '0'+str(mes)
    initial_1 = str(dia)+"/"+str(mes) +"/"+str(anio)

    try:
        f = "%d/%m/%y"        
        initial_2 = datetime.strptime(initial_1 , f)
    except Exception as r:
        f = "%m/%d/%y"        
        initial_2 = datetime.strptime(initial_1 , f)
    fecha = initial_2
    fecha = difMonth(fecha, value)
    return str(fecha.strftime("%d/%m/%y"))

def obtenerVencimiento (index, date, inicio, fin):
    inicio = str(inicio.strftime("%d/%m/%y"))
    fin = str(fin.strftime("%d/%m/%y"))
    # date = str(date.strftime("%d/%m/%y"))
    date_initial = str(date).split('/')
    dia = int(date_initial[0])
    mes = int(date_initial[1])
    anio = int(date_initial[2])

    # if index == 0:
    #     dia = dia + periodo_inicial
    # else:
    #     dia = dia + periodo_subsecuente

    if mes == 4 or mes == 6 or mes == 9 or mes == 11:
        if dia > 30:
            dia = dia - 30
            mes = mes + 1
            if mes > 12:
                mes = mes - 12
                anio = anio + 1          
    elif mes == 2:
        if dia > 28:
          dia = dia - 28
          mes = mes + 1
        
    else:
        if dia > 31:
          dia = dia - 31
          mes = mes + 1
          if mes > 12:
            mes = mes - 12
            anio = anio + 1        
        
    if len(str(dia)) == 1:
        dia = '0' + str(dia)

    if len(str(mes)) == 1:
        mes = '0' + str(mes)
    return str(dia) + '/' + str(mes) + '/' + str(anio)

