@api_view(['POST'])
@pm((IsAuthenticatedV2, IsOrgMemberV2))
def RehabilitarPoliza(request):
    data = request.data
    motivo_rehabilitacion = data['motivo_rehabilitacion']
    poliza_id = data['id']
    poliza = Polizas.objects.get(id = poliza_id)
    if poliza.status == 2:
        poliza.status = 1
    else:
        poliza.status = 14 

    # if OldPolicies.objects.filter(new_policy__id = poliza.id).exists():
    #     historic = OldPolicies.objects.filter(new_policy__id = poliza.id).first()
    #     poliza_base = historic.base_policy
    #     # poliza_base.renewed_status = 2
    #     poliza_base.save()
    poliza.renewed_status=0#https://miurabox.atlassian.net/browse/DES-661
    # if OldPolicies.objects.filter(base_policy__id = poliza.id).exists():
    #     if not OldPolicies.objects.filter(base_policy__id = poliza.id, new_policy__status__in=[1,10,14]).exists():
    #         poliza.renewed_status=0
    poliza.reason_rehabilitate = motivo_rehabilitacion
    poliza.save()

    Recibos.objects.filter(
        poliza = poliza, 
        receipt_type = 1, 
        status = 2
    ).update(
        status = 4
    )
    poliza.save()
    if poliza.cancelnotas:
        Recibos.objects.filter(
            poliza = poliza, 
            receipt_type = 3, 
            status = 2
        ).update(
            status = 4
        )
    
    if poliza.document_type == 3:
        Polizas.objects.filter(
            caratula = poliza.id, 
            document_type = 6, 
            certificado_inciso_activo = False
        ).update(certificado_inciso_activo = True)

    
    return Response(status = 200)

