class PolizasVendedorViewSet(viewsets.ModelViewSet):
    serializer_class = PolizaVendorSerializer
    permission_classes = (IsAuthenticatedV2, IsOrgMemberV2)

    def get_queryset(self):
        org_name=self.request.GET.get('org')
        vendedor = self.request.GET.get('vendedor')
        pf_status_exclude = [1,2,11,0]
        polizas_filter = []
        polizas_aux = []
        polizas = []
        # direct_policies =  Polizas.objects.filter(org_name = self.request.GET.get('org'), ref_policy__referenciador__id__in = [vendedor],ref_policy__is_changed = False).exclude(status__in =pf_status_exclude)
        direct_policies = Polizas.objects.filter(org_name=self.request.GET.get('org'),ref_policy__referenciador__id__in=[vendedor]).exclude(status__in=pf_status_exclude,ref_policy__is_changed=True)

        for dp in direct_policies:
            if not dp in polizas:
                polizas.append(dp)
        
        contractor_ = Contractor.objects.filter(org_name = self.request.GET.get('org'),vendor = vendedor).values_list('pk', flat=True)

        p1 = Polizas.objects.exclude(status__in = pf_status_exclude).exclude(ref_policy__is_changed=True).filter(org_name = self.request.GET.get('org'),contractor__in = list(contractor_))

        for p in p1:
            if not p in polizas_filter:
                polizas_filter.append(p)
        

        for poliza in polizas_filter:
            refs = ReferenciadoresInvolved.objects.filter(policy = poliza,is_changed=False)
            for y in refs:   
                if not y.referenciador.id:
                    if not poliza in polizas_aux:
                        polizas_aux.append(poliza)
                else:
                    if poliza.contractor:
                        for y in refs:                        
                            if poliza.contractor.vendor.id != y.referenciador.id:
                                continue
                            else:
                                if not poliza in polizas_aux:
                                    polizas_aux.append(poliza)       

        for p in polizas_aux:
            if not p in polizas:
                polizas.append(p)
        return polizas

