@api_view(['GET'])
@pm((IsAuthenticatedV2, IsOrgMemberV2))
def getEndorsementColectForAdjust(request):
    org_name = request.GET.get('org')
    poliza_id = request.GET.get('policy')

    if not org_name or not poliza_id:
        return JsonResponse({'detail': 'Faltan parámetros org o policy'}, status=400)

    try:
        polizaObject = Polizas.objects.get(id=poliza_id, org_name=org_name)
    except Polizas.DoesNotExist:
        return JsonResponse({'detail': 'Póliza no encontrada'}, status=404)

    endososGeneral = Endorsement.objects.filter(
        policy_id=poliza_id,
        org_name=org_name,
        status=2,
    ).exclude(status=0).distinct()

    queryset = endososGeneral
    queryExclude = Endorsement.objects.none()

    if polizaObject.document_type == 3 and polizaObject.administration_type == 2:
        endososConRecibosIds = Recibos.objects.filter(
            poliza_id=poliza_id,
            org_name=org_name,
            endorsement__isnull=False,
        ).values_list('endorsement_id', flat=True).distinct()

        queryExclude = endososGeneral.filter(id__in=endososConRecibosIds)
        queryset = endososGeneral.exclude(id__in=endososConRecibosIds)

    endorsements_ser = EndorsementHyperSerializer(queryset, context={'request': request}, many=True)
    excluidos_ser = EndorsementHyperSerializer(queryExclude, context={'request': request}, many=True)

    excluidos_data = excluidos_ser.data
    for item in excluidos_data:
        item['motivo_exclusion'] = 'Endoso con generación de recibos activa'

    return JsonResponse({
        'endosos': endorsements_ser.data,
        'excluídos': excluidos_data,
    })

