class GetCertificadosViewset(viewsets.ModelViewSet):
    serializer_class = CertificateSerializer
    permission_classes = (IsAuthenticatedV2, )

    def get_queryset(self):        
        parent = self.request.GET.get('parent')
        active = self.request.GET.get('active')

        if parent:
            certificados = Polizas.objects.filter(parent = parent, org_name=self.request.GET.get('org'), document_type = 6).exclude(status = 0).order_by("id")
            if int(active) == 1:
                certificados = certificados.exclude(certificado_inciso_activo = False)
            else:
                certificados = certificados.exclude(certificado_inciso_activo = True)
 
            list_c = []
            for p in certificados:

                if not p.certificate_number is None:
                    list_c.append(p.certificate_number)
        else:
            caratula = self.request.GET.get('caratula')
            certificados = Polizas.objects.filter(caratula = caratula, org_name=self.request.GET.get('org'), document_type = 6).exclude(certificado_inciso_activo = False).exclude(status = 0).order_by("id")


        return certificados

