def checkProcAuto(request):
    switcher = {
        1: "Residencia",
        2: "Turista",
        4: "Legalizado",
        10: "Fronterizo",
        11: "Cancelada",
        0: "--",
    }
    return switcher.get(request, "--")
def checkCargaAuto(request):
    switcher = {
        1: "A",
        2: "B",
        4: "C",
        0: "--",
    }
    return switcher.get(request, "--")

