@api_view(['POST'])
@pm((IsAuthenticatedV2, ))
def get_assign(request):
    try:
        obj = Assign.objects.filter(poliza = request.data['poliza'])
        s2 = AssignSerializer(obj,context={'request': request}, many=True)
        obj2 = Pendients.objects.filter(poliza = request.data['poliza'])
        serializer = pendientsSerializer(obj2,context={'request': request}, many=True) 
        response = []
        for o in serializer.data:
            response.append(o)
        for i in s2.data:
            response.append(i)
        if request.user.is_superuser:
            return Response(response)
        session = Session.objects.get(username= request.user.username)
        pmscg = session.permissions['SAAM']['Pólizas']
        for pm in pmscg:
            if pm['name'] == 'Ver correo electrónico de asegurados':
                if pm['checked'] == True:
                    return Response(response)        
        return Response([])
    except Exception as e:
        return Response(status=status.HTTP_404_NOT_FOUND)

@api_view(['GET'])
@pm((IsAuthenticatedV2, ))
def delete_assign(request):
    try:
        obj = Assign.objects.get(pk = request.GET.get('id'))
        obj.delete()
        return Response({'status': 'Objeto eliminado'})
    except:
        try:
            obj = Pendients.objects.get(pk = request.GET.get('id'))
            obj.delete()
            return Response({'status': 'Objeto eliminado'})
        except Exception as e:
            return Response(status=status.HTTP_404_NOT_FOUND)
    
