@api_view(['GET'])
#@pm((IsAuthenticatedV2, ))
@pm((IsAuthenticatedV2, IsOrgMemberV2)) # suggest
def exist_serial(request, pk):
    autos = AutomobilesDamages.objects.filter(serial=pk, org_name=request.GET.get('org'))
    for auto in autos:
        if auto.policy.document_type ==6:
            if (auto.policy.parent.parent.parent.status ==14 or auto.policy.parent.parent.parent.status ==10):
                return Response(data={'exist': True, 'poliza': auto.policy.poliza_number}, status=status.HTTP_200_OK)
        if auto.policy.document_type ==1 or auto.policy.document_type ==12:
            if (auto.policy.status == 14 or auto.policy.status == 10):
                return Response(data={'exist': True, 'poliza': auto.policy.poliza_number}, status=status.HTTP_200_OK)
    
    return Response(data=False)

