@api_view(['GET','POST'])
@pm((IsAuthenticatedV2, ))
def PendientsViewSet(request):
    if request.method == 'POST':
        serializer = pendientsSerializer(data=request.data)
        if serializer.is_valid():
            poliza = Polizas.objects.get(id = request.data['poliza'])
            if User.objects.filter(email__iexact = request.data['email'],is_active = True).exists():
                users = User.objects.filter(email__iexact = request.data['email'],is_active = True)
                for user in users:
                    if not Assign.objects.filter(poliza = poliza, user=user).exists():
                        obj = Assign(
                            user = user,
                            poliza = poliza,
                            is_owner = request.data['is_owner'],
                            active = request.data['active']
                            )
                        obj.save()                    
                return Response({'status':'Created','type':1})
            else:
                if not Pendients.objects.filter(poliza = poliza,email__iexact=request.data['email']).exists():
                    obj = Pendients(
                        email = request.data['email'],
                        poliza = poliza,
                        is_owner = request.data['is_owner'],
                        active = request.data['active']
                        )
                    obj.save()
                    return Response({'status':'Se ha compartido por email: '+str(request.data['email']),'type':2})
                else:
                    return Response({'status':'Ya se ha compartido por email a: '+str(request.data['email']),'type':2})
            # LOG 
            if poliza.document_type==3:
                model = 18 
                tipo = ' la colectividad: '
                number = poliza.poliza_number
            elif poliza.document_type == 6:
                model = 25
                tipo = ' el certificado: '
                number = poliza.certificate_number 
            elif poliza.document_type == 1:
                model = 1
                tipo = ' la póliza: '
                number = poliza.poliza_number
            else:
                model = 1
                tipo = ' la póliza: '
                number = poliza.poliza_number
            dataIdent = ' compartio' +str(tipo)+str(number)
            original = {}
            change= dataIdent                    
            try:
                send_log_complete(request.user, org_name, 'POST', model, '%s' % str(dataIdent),'%s' % str(original),'%s' % str(change), caratula.id)
            except Exception as eee:
                pass
            # LOG---
    elif request.method == 'GET':
        obj = Pendients.objects.filter(poliza =request.data['poliza'])
        serializer = pendientsSerializer(obj,context={'request': request}, many=True)
        return Response(serializer.data)

