from .utils_share import safe_send_one_certificate_email_only,safe_send_one_certificate
@api_view(['GET','POST'])
@pm((IsAuthenticatedV2, ))
def shareCertificatesToEmail_862(request):
    org_name = request.GET.get('org')
    remitente, logo, logo_mini = user_remitente(request)

    if request.method != 'POST':
        return Response({'detail': 'Método no permitido'}, status=405)

    # plantilla
    plantillaSeleccionada = None
    try:
        plantilla = request.data.get('plantilla')
        if plantilla:
            plantillaSeleccionada = EmailTemplate.objects.get(id=int(plantilla), org_name=org_name)
    except Exception:
        plantillaSeleccionada = None

    org_info = get_org_info(request)
    direccion = org_info.get('address', '')

    first_comment = request.data.get('first_comment') or ''
    second_comment = request.data.get('second_comment') or ''
    subjectEmail = request.data.get('subjectEmail') or ''

    caratula = Polizas.objects.get(pk=request.data['id_poliza'], document_type=3, org_name=org_name)
    certificados = Polizas.objects.filter(
        caratula=str(request.data['id_poliza']),
        document_type=6,
        certificado_inciso_activo=True
    ).distinct('id')

    # ✅ crea batch (EMAIL ONLY)
    batch = CertificateShareBatch.objects.create(
        org_name=org_name,
        caratula=caratula,
        template=plantillaSeleccionada,
        subject=subjectEmail,
        first_comment=first_comment,
        second_comment=second_comment,
        created_by=request.user,
        status='RUNNING',
        total=certificados.count(),
        sent=0,
        failed=0,
        started_at=timezone.now(),
    )

    # crea items
    items_map = {}
    for cer in certificados:
        it = CertificateShareBatchItem.objects.create(
            batch=batch,
            certificate=cer,
            certificate_number=(cer.certificate_number or ''),
            status='PENDING',
            attempts=0,
        )
        items_map[cer.id] = it

    sent_count = 0
    failed_count = 0
    failed_list = []

    for cer in certificados:
        it = items_map.get(cer.id)
        it.attempts = (it.attempts or 0) + 1
        it.save()

        r = safe_send_one_certificate_email_only(
            request=request,
            org_info=org_info,
            caratula=caratula,
            cer=cer,
            plantillaSeleccionada=plantillaSeleccionada,
            first_comment=first_comment,
            second_comment=second_comment,
            subjectEmail=subjectEmail,
            logo=logo,
            logo_mini=logo_mini,
            direccion=direccion,
            folder=folder
        )

        it.receiver_email = r.get('receiver_email', '') or it.receiver_email
        print('receiveeeeeeeeee',it)
        if r.get('sent'):
            it.status = 'SENT'
            it.sent_at = timezone.now()
            it.error_message = ''
            it.error_trace = ''
            sent_count += 1
        else:
            it.status = 'FAILED'
            it.error_message = (r.get('error_message', '') or '')[:2000]
            it.error_trace = (r.get('error_trace', '') or '')[:8000]
            failed_count += 1
            failed_list.append({
                'item_id': it.id,
                'certificate_id': cer.id,
                'certificate_number': it.certificate_number,
                'email': it.receiver_email,
                'error': it.error_message
            })

        it.save()

        # progreso
        batch.sent = sent_count
        batch.failed = failed_count
        batch.save()

    batch.status = 'DONE'
    batch.finished_at = timezone.now()
    batch.sent = sent_count
    batch.failed = failed_count
    batch.save()

    return Response({
        'status': 'DONE',
        'batch_id': batch.id,
        'total': batch.total,
        'sent': batch.sent,
        'failed': batch.failed,
        'failed_items': failed_list[:200],
    })
from django.utils import timezone
from rest_framework.response import Response

@api_view(['GET','POST'])
@pm((IsAuthenticatedV2, ))
def shareCertificatesToAppEmail_862(request):
    remitente, logo, logo_mini = user_remitente(request)
    org_name = request.GET.get('org')

    if request.method == 'POST':
        # 1) lee plantilla
        plantillaSeleccionada = None
        try:
            plantilla = request.data.get('plantilla')
            if plantilla:
                plantillaSeleccionada = EmailTemplate.objects.get(id=int(plantilla), org_name=org_name)
        except Exception:
            plantillaSeleccionada = None

        org_info = get_org_info(request)
        direccion = org_info.get('address', '')

        first_comment = request.data.get('first_comment') or ''
        second_comment = request.data.get('second_comment') or ''
        subjectEmail = request.data.get('subjectEmail') or ''
        caratula = Polizas.objects.get(pk=request.data['id_poliza'], document_type=3, org_name=org_name)

        certificados = Polizas.objects.filter(
            caratula=str(request.data['id_poliza']),
            document_type=6,
            certificado_inciso_activo=True
        ).distinct('id')

        # 2) crea batch
        batch = CertificateShareBatch.objects.create(
            org_name=org_name,
            caratula=caratula,
            template=plantillaSeleccionada,
            subject=subjectEmail,
            first_comment=first_comment,
            second_comment=second_comment,
            created_by=request.user,
            status='RUNNING',
            total=certificados.count(),
            started_at=timezone.now()
        )

        # 3) crea items PENDING
        items_by_cert_id = {}
        for cer in certificados:
            it = CertificateShareBatchItem.objects.create(
                batch=batch,
                certificate=cer,
                certificate_number=(cer.certificate_number or ''),
                status='PENDING',
                attempts=0
            )
            items_by_cert_id[cer.id] = it

        sent_count = 0
        failed_count = 0
        failed_list = []

        # 4) proceso tolerante a errores
        for cer in certificados:
            it = items_by_cert_id.get(cer.id)
            it.attempts = (it.attempts or 0) + 1
            it.save()

            r = safe_send_one_certificate(
                request=request,
                org_info=org_info,
                caratula=caratula,
                cer=cer,
                plantillaSeleccionada=plantillaSeleccionada,
                first_comment=first_comment,
                second_comment=second_comment,
                subjectEmail=subjectEmail,
                logo=logo,
                logo_mini=logo_mini,
                direccion=direccion,
                folder=folder
            )

            it.receiver_email = r.get('receiver_email', '') or ''

            if r.get('sent'):
                it.status = 'SENT'
                it.sent_at = timezone.now()
                it.error_message = ''
                it.error_trace = ''
                sent_count += 1
            else:
                it.status = 'FAILED'
                it.error_message = r.get('error_message', '')[:2000]
                it.error_trace = (r.get('error_trace', '') or '')[:8000]
                failed_count += 1
                failed_list.append({
                    'certificate_id': cer.id,
                    'certificate_number': it.certificate_number,
                    'email': it.receiver_email,
                    'error': it.error_message
                })

            it.save()

            # opcional: persistir progreso en batch cada N items
            batch.sent = sent_count
            batch.failed = failed_count
            batch.save()

        batch.status = 'DONE'
        batch.finished_at = timezone.now()
        batch.sent = sent_count
        batch.failed = failed_count
        batch.save()

        # 5) resumen final al usuario
        return Response({
            'status': 'DONE',
            'batch_id': batch.id,
            'total': batch.total,
            'sent': batch.sent,
            'failed': batch.failed,
            'failed_items': failed_list[:200]  # evita respuestas gigantes
        })

