@api_view(['GET'])
@pm((IsAuthenticatedV2, ))
def share_certificates_batches(request):
    org_name = request.GET.get('org')
    id_poliza = request.GET.get('id_poliza')  # carátula id
    page = int(request.GET.get('page') or 1)
    page_size = int(request.GET.get('page_size') or 20)

    qs = CertificateShareBatch.objects.filter(org_name=org_name).order_by('-id')

    # filtra por carátula si llega
    if id_poliza:
        qs = qs.filter(caratula_id=int(id_poliza))

    # (opcional) solo los míos
    # qs = qs.filter(created_by=request.user)

    paginator = Paginator(qs, page_size)
    page_obj = paginator.page(page)

    batches = []
    for b in page_obj.object_list:
        created_by = ''
        try:
            created_by = b.created_by.get_full_name() or b.created_by.email
        except Exception:
            created_by = ''

        batches.append({
            'id': b.id,
            'status': b.status,
            'total': b.total,
            'sent': b.sent,
            'failed': b.failed,
            'subject': b.subject,
            'template_id': b.template_id,
            'created_by': created_by,
            'created_at': b.created_at.isoformat() if b.created_at else None,
            'started_at': b.started_at.isoformat() if b.started_at else None,
            'finished_at': b.finished_at.isoformat() if b.finished_at else None,
        })

    return Response({
        'pagination': {
            'page': page,
            'page_size': page_size,
            'pages': paginator.num_pages,
            'count': paginator.count,
        },
        'batches': batches
    })
@api_view(['GET'])
@pm((IsAuthenticatedV2, ))
def share_certificates_batch_items(request, batch_id):
    org_name = request.GET.get('org')

    batch = CertificateShareBatch.objects.get(id=batch_id, org_name=org_name)

    qs = CertificateShareBatchItem.objects.filter(batch=batch).order_by('-id')

    status = request.GET.get('status')
    if status:
        qs = qs.filter(status=status)

    page = int(request.GET.get('page') or 1)
    page_size = int(request.GET.get('page_size') or 50)

    paginator = Paginator(qs, page_size)
    page_obj = paginator.page(page)

    items = []
    for it in page_obj.object_list:
        items.append({
            'id': it.id,
            'certificate_id': it.certificate_id,
            'certificate_number': it.certificate_number,
            'receiver_email': it.receiver_email,
            'status': it.status,
            'attempts': it.attempts,
            'sent_at': it.sent_at.isoformat() if it.sent_at else None,
            'updated_at': it.updated_at.isoformat() if it.updated_at else None,
            'error_message': it.error_message,
        })

    return Response({
        'batch': {
            'id': batch.id,
            'status': batch.status,
            'caratula': batch.caratula.id if batch.caratula else None,
            'total': batch.total,
            'sent': batch.sent,
            'failed': batch.failed,
            'started_at': batch.started_at.isoformat() if batch.started_at else None,
            'finished_at': batch.finished_at.isoformat() if batch.finished_at else None,
        },
        'pagination': {
            'page': page,
            'page_size': page_size,
            'pages': paginator.num_pages,
            'count': paginator.count,
        },
        'items': items
    })
@api_view(['POST'])
@pm((IsAuthenticatedV2, ))
def share_certificates_batch_retry_failed(request, batch_id):
    org_name = request.GET.get('org')
    batch = CertificateShareBatch.objects.get(id=batch_id, org_name=org_name)

    # Si quieres: evita reintentos si está RUNNING
    if batch.status == 'RUNNING':
        return Response({'detail': 'Batch en proceso'}, status=400)

    caratula = batch.caratula
    plantilla = batch.template
    org_info = get_org_info(request)
    direccion = org_info.get('address', '')
    logo, logo_mini = user_remitente(request)[1:3]

    first_comment = batch.first_comment or ''
    second_comment = batch.second_comment or ''
    subjectEmail = batch.subject or ''

    failed_items = CertificateShareBatchItem.objects.filter(batch=batch, status='FAILED').order_by('id')

    resent = 0
    still_failed = 0
    results = []

    batch.status = 'RUNNING'
    batch.started_at = timezone.now()
    batch.save()

    for it in failed_items:
        it.attempts = (it.attempts or 0) + 1
        it.error_message = ''
        it.error_trace = ''
        it.status = 'PENDING'
        it.save()

        cer = it.certificate  # Polizas
        r = safe_send_one_certificate(
            request=request,
            org_info=org_info,
            caratula=caratula,
            cer=cer,
            plantillaSeleccionada=plantilla,
            first_comment=first_comment,
            second_comment=second_comment,
            subjectEmail=subjectEmail,
            logo=logo,
            logo_mini=logo_mini,
            direccion=direccion,
            folder=folder
        )

        it.receiver_email = r.get('receiver_email', '') or it.receiver_email

        if r.get('sent'):
            it.status = 'SENT'
            it.sent_at = timezone.now()
            it.error_message = ''
            it.error_trace = ''
            resent += 1
        else:
            it.status = 'FAILED'
            it.error_message = (r.get('error_message', '') or '')[:2000]
            it.error_trace = (r.get('error_trace', '') or '')[:8000]
            still_failed += 1

        it.save()

        results.append({
            'item_id': it.id,
            'certificate_number': it.certificate_number,
            'email': it.receiver_email,
            'status': it.status,
            'error_message': it.error_message,
        })

    # Recalcula contadores del batch
    batch.sent = CertificateShareBatchItem.objects.filter(batch=batch, status='SENT').count()
    batch.failed = CertificateShareBatchItem.objects.filter(batch=batch, status='FAILED').count()
    batch.status = 'DONE'
    batch.finished_at = timezone.now()
    batch.save()

    return Response({
        'status': 'DONE',
        'batch_id': batch.id,
        'resent': resent,
        'still_failed': still_failed,
        'results': results[:200],
    })
