#Buscar poliza siniestros
class BuscarAfectadoPorNumPoliza(viewsets.ModelViewSet):
    serializer_class = PolizaSiniesterSerializer
    permission_classes = (IsAuthenticatedV2,)

    def get_queryset(self):
        result = []
        polizas = None
        num_poliza = self.request.GET.get('num_poliza')
        if num_poliza !='0':
            polizas = Polizas.objects.filter(org_name=self.request.GET.get('org'),poliza_number=num_poliza,document_type__in = list([1,6,3])).exclude(status = 0).order_by('id').reverse()

        if 'id_policy' in self.request.GET:
            try:
                polizas = Polizas.objects.filter(org_name=self.request.GET.get('org'),pk= self.request.GET.get('id_policy'),
                document_type__in = list([1,6,3])).exclude(status = 0).order_by('id').reverse()
            except Exception as rt:
                polizas = []
                print('error buscar afectado por #pol',rt)

        if polizas:
            result = list(polizas)
        else:
            result = None
        return  result

