@api_view(['GET'])
@permission_classes((IsAuthenticatedV2,))
def obtenerProveedoresUsuarioApp(request,username):
    try:
        user = User.objects.get(username=username)
    except:
        return Response({'error':'No existe el usuario'})
    queryset = Assign.objects.filter(user = user).exclude(poliza__status = 15)

    if user.email:
        queryset_ = Pendients.objects.filter(email__iexact = user.email)
    else:
        queryset_ = []    

    if not queryset.exists() and not queryset_.exists():
        return Response({'error':'No existen polizas asignadas a ese usuario'})

    providers = []
    for poliza in queryset:
        if poliza.poliza.document_type == 1:
            if poliza.poliza.status in [14, 10]:
                if not poliza.poliza.aseguradora in providers:
                    providers.append(poliza.poliza.aseguradora)
        elif poliza.poliza.document_type == 6:
            if poliza.poliza.parent.parent.parent.status in [14, 10]:
                if poliza.poliza.aseguradora:
                    if not poliza.poliza.aseguradora in providers:
                        providers.append(poliza.poliza.parent.parent.parent.aseguradora)
                elif poliza.poliza.parent:
                    if poliza.poliza.parent.aseguradora:
                        if not poliza.poliza.parent.parent.aseguradora in providers:
                            providers.append(poliza.poliza.parent.parent.aseguradora)
                    elif poliza.poliza.parent.parent:
                        if poliza.poliza.parent.parent.aseguradora:
                            if not poliza.poliza.parent.parent.aseguradora in providers:
                                providers.append(poliza.poliza.parent.parent.aseguradora)
                        elif poliza.poliza.parent.parent.parent:
                            if poliza.poliza.parent.parent.parent.aseguradora:
                                if not poliza.poliza.parent.parent.parent.aseguradora in providers:
                                    providers.append(poliza.poliza.parent.parent.parent.aseguradora)

    if queryset_:
            for poliza in queryset_:
                if poliza.poliza.document_type == 1:
                    if poliza.poliza.status  in [14, 10]:
                        if not poliza.poliza.aseguradora in providers:
                            providers.append(poliza.poliza.aseguradora)
                elif poliza.poliza.document_type == 6:
                    if poliza.poliza.parent:
                        if poliza.poliza.parent.parent:
                            if poliza.poliza.parent.parent.parent:
                                if poliza.poliza.parent.parent.parent.status  in [14, 10]:
                                    if poliza.poliza.parent.parent.parent.aseguradora:
                                        if not poliza.poliza.aseguradora in providers:
                                            providers.append(poliza.poliza.parent.parent.parent.aseguradora)
                                    elif poliza.poliza.parent:
                                        if poliza.poliza.parent.aseguradora:
                                            if not poliza.poliza.parent.parent.aseguradora in providers:
                                                providers.append(poliza.poliza.parent.parent.aseguradora)
                                        elif poliza.poliza.parent.parent:
                                            if poliza.poliza.parent.parent.aseguradora:
                                                if not poliza.poliza.parent.parent.aseguradora in providers:
                                                    providers.append(poliza.poliza.parent.parent.aseguradora)
                                            elif poliza.poliza.parent.parent.parent:
                                                if poliza.poliza.parent.parent.parent.aseguradora:
                                                    if not poliza.poliza.parent.parent.parent.aseguradora in providers:
                                                        providers.append(poliza.poliza.parent.parent.parent.aseguradora)


    serializer = ProviderReadListClaveSerializer(providers, context = {'request': request}, many = True)
    return Response(serializer.data)


class PolizasPagination(PageNumberPagination):
    """Controla la paginación de pólizas"""
    page_size = 10
    page_size_query_param = 'page_size'
    max_page_size = 50


@api_view(['GET'])
@pm((IsAuthenticatedV2,))
def PolizasByUserPaginado(request, username=None):
    """
    Retorna las pólizas activas, próximas a iniciar o asignadas al usuario autenticado
    o indicado por `username`, con soporte de paginación real.
    """
    # --- Usuario destino ---
    try:
        user = User.objects.get(username=username) if username else request.user
    except User.DoesNotExist:
        return Response({'error': 'No existe el usuario especificado'}, status=404)
    # user = User.objects.get(id=23518)
    today = date.today()

    # --- Asignaciones directas ---
    asignadas_ids = Assign.objects.filter(
        user=user,
        poliza__document_type__in=[1, 12],
        poliza__status__in=[10, 14]
    ).values_list('poliza_id', flat=True)

    asignadas_proximas_ids = Assign.objects.filter(
        user=user,
        poliza__document_type__in=[1, 12],
        poliza__status=12,
        poliza__end_of_validity__gte=today
    ).values_list('poliza_id', flat=True)

    # --- Carátulas y certificados relacionados ---
    caratulas_ids = Polizas.objects.filter(
        document_type__in=[3, 11],
        status__in=[10, 14]
    ).values_list('id', flat=True)

    caratulasR_ids = Polizas.objects.filter(
        document_type__in=[3, 11],
        status=12,
        end_of_validity__gte=today
    ).values_list('id', flat=True)

    certificados_ids = Assign.objects.filter(
        user=user,
        poliza__document_type__in=[6, 12],
        poliza__caratula__in=list(caratulas_ids) + list(caratulasR_ids)
    ).values_list('poliza_id', flat=True)

    # --- Pendientes por correo ---
    pendientes_ids = []
    if user.email:
        pendientes_ids = Pendients.objects.filter(
            email__iexact=user.email,
            poliza__document_type__in=[1, 12],
            poliza__status__in=[10, 12, 14]
        ).values_list('poliza_id', flat=True)

    # --- Consolidar todas las IDs ---
    polizas_ids = list(set(asignadas_ids) | set(asignadas_proximas_ids) | set(certificados_ids) | set(pendientes_ids))

    if not polizas_ids:
        return Response({'error': 'No existen pólizas vigentes o por iniciar asignadas a ese usuario'}, status=404)

    # --- Query optimizada ---
    polizas_qs = (
        Polizas.objects.filter(id__in=polizas_ids)
        .select_related('aseguradora', 'ramo', 'subramo', 'contractor', 'paquete')
        .distinct()
        .order_by('-id')
    )

    # --- Paginación ---
    paginator = PolizasPagination()
    page = paginator.paginate_queryset(polizas_qs, request)
    serializer = PolizaListAppLiteSerializer(page, context={'request': request}, many=True)

    return paginator.get_paginated_response(serializer.data)

