@api_view(['POST'])
@permission_classes((IsAuthenticatedV2,))
def obtenerDataForNotsUsuarioApp(request,username):
    groupinglevel = None
    contractor = None
    aseguradora = None
    ramoscode = None
    aseguradoras = None
    ramos = None
    aseg2 = None
    aseg3 = None
    aseg4 = None
    ramoscode2 = None
    ramoscode3 = None
    ramoscode4 = None
    # o importan solo las de la org  
    if 'glevel' in request.data:
        if  request.data['glevel']:
            nivel = GroupingLevel.objects.filter(id = request.data['glevel'],type_grouping = 1,org_name = request.GET.get('org'))
            nivel2 = GroupingLevel.objects.filter(parent__id = nivel[0].id,type_grouping = 2,org_name = request.GET.get('org'))
            nivel3 = GroupingLevel.objects.filter(parent__id = nivel[0].id,type_grouping = 3,org_name = request.GET.get('org'))
            niveles = (nivel) | (nivel2) | (nivel3)
            contractor = Contractor.objects.filter(groupinglevel__id__in = niveles, org_name = request.GET.get('org'), is_active = True) 
              # contractor = Contractor.objects.filter(Q(groupinglevel__id = request.data['glevel']) |
            #     Q(groupinglevel__parent__id = request.data['glevel']) |
            #     Q(groupinglevel__parent__parent__id = request.data['glevel']) |
            #     Q(groupinglevel__parent__parent__id = request.data['glevel']), org_name = request.GET.get('org'), is_active = True) 
            asegs = Polizas.objects.filter(Q(contractor__id__in = contractor.values_list('pk',flat = True)) |
                Q(parent__contractor__id__in = contractor.values_list('pk',flat = True)) | 
                Q(parent__parent__contractor__id__in = contractor.values_list('pk',flat = True)) | 
                Q(parent__parent__parent__contractor__id__in = contractor.values_list('pk',flat = True)),
                org_name = request.GET.get('org')).exclude(status = 0).exclude(status = 15)
            aseguradora = asegs.exclude(aseguradora =None).distinct('aseguradora__id').values_list('aseguradora__id',flat = True)
            aseg2 = asegs.exclude(parent__aseguradora =None).distinct('parent__aseguradora__id').values_list('parent__aseguradora__id',flat = True)
            aseg3 = asegs.exclude(parent__parent__aseguradora =None).distinct('parent__parent__aseguradora__id').values_list('parent__parent__aseguradora__id',flat = True)
            aseg4 = asegs.exclude(parent__parent__parent__aseguradora =None).distinct('parent__parent__parent__aseguradora__id').values_list('parent__parent__parent__aseguradora__id',flat = True)
            aseguradora = Provider.objects.filter(Q(id__in = aseguradora) | Q(id__in = aseg2) | Q(id__in = aseg3) | Q(id__in = aseg4),org_name = request.GET.get('org'))
            # aseguradora = Provider.objects.filter(id__in = aseguradoras,org_name = request.GET.get('org'))
            ramos = Ramos.objects.filter(provider__id__in = aseguradora, org_name = request.GET.get('org'))          

    groupinglevels = GroupingLevel.objects.filter(org_name = request.GET.get('org'), type_grouping = 1)
    contractors = contractor
    aseguradoras = aseguradora.distinct('id')
    ramos = ramos.distinct('ramo_code')

    glevs_serializer= GroupingLevelHyperSerializer(groupinglevels, context = {'request': request}, many = True)    
    conts_serializer= ContractorsResumeSerializer(contractors, context = {'request': request}, many = True)
    aseg_serializer= ProviderReadListClaveSerializer(aseguradoras, context = {'request': request}, many = True)
    ramo_serializer= RamosHyperSerializer(ramos, context = {'request': request}, many = True)

    data = {'GroupingLevel': glevs_serializer.data if groupinglevels else None,
        'Contractors': conts_serializer.data if contractors else None,
        'Aseguradoras': aseg_serializer.data if aseguradoras else None,
        'Ramos': ramo_serializer.data if ramos else None,
        }
    return JsonResponse(data)

