    pendingOrange = polizas.filter(status__in = [1, 5], org_name =  request.GET.get('org'), created_at__lte = diasY, created_at__gt = diasO)
    pendingRed = polizas.filter(status__in = [1, 5], org_name =  request.GET.get('org'), created_at__lte = diasO)
