from dateutil.relativedelta import relativedelta

@api_view(['GET'])
#@pm((IsAuthenticatedV2, RenovacionesChartPermissions))
@pm((IsAuthenticatedV2, RenovacionesChartPermissionsV2))
def renewals_initial(request):
    user = request.META['user']
    try:
        config_chart = Graphics.objects.filter(org_name =  user['org']['name'], type_graphic = 3).order_by('-created_at')[0]
        days_green = config_chart.green
        days_yellow = config_chart.yellow
        days_orange = config_chart.orange
        days_red = config_chart.red
    except Graphics.DoesNotExist:
        config_chart = None
        days_green = 60
        days_yellow = 40
        days_orange = 20
        days_red = 0
    except: 
        config_chart = None
        days_green = 60
        days_yellow = 40
        days_orange = 20
        days_red = 0


    try:
        today = datetime.today()
    except:
        today = datetime.datetime.today()
    orange_days = timedelta(days = days_orange)
    yellow_days = timedelta(days = days_yellow)
    green_days = timedelta(days = days_green)

    diasO = today + orange_days
    diasY = today + yellow_days
    diasG = today + green_days

