# carga masiva pdf a certificados por nombre de titular
# views.py
import os
import json
from rest_framework.views import APIView
from rest_framework.parsers import MultiPartParser, FormParser
from rest_framework.response import Response
from rest_framework import status

from .utils import normalize_name
from .models import MassivePDFBatch, MassivePDFBatchItem
def get_person_name(personal):
    if not personal:
        return 'Sin asegurado'

    full = getattr(personal, 'full_name', None)
    if full and full.strip():
        return full.strip()

    parts = []
    first = getattr(personal, 'first_name', None)
    last = getattr(personal, 'last_name', None)
    second_last = getattr(personal, 'seconda_last_name', None)  # tu campo

    if first and first.strip():
        parts.append(first.strip())
    if last and last.strip():
        parts.append(last.strip())
    if second_last and second_last.strip():
        parts.append(second_last.strip())

    return ' '.join(parts) if parts else 'Sin asegurado'

class MassivePDFUploadView(APIView):
    parser_classes = (MultiPartParser, FormParser)
    permission_classes = (IsAuthenticatedV2, IsOrgMemberV2)
    def post(self, request, policy_id):
        files = request.FILES.getlist('arch')          # binarios
        names = request.data.getlist('nombre')         # strings (puede venir repetido)
        owner = request.data.get('owner')              # caratula id (opcional, ya viene en URL)
        org_name = request.GET.get('org')

        if not org_name:
            return Response({'detail': 'Falta org.'}, status=status.HTTP_400_BAD_REQUEST)

        if not files:
            return Response({'detail': 'No se recibieron archivos.'}, status=status.HTTP_400_BAD_REQUEST)

        # Carátula póliza grupo
        caratula = Polizas.objects.get(id=policy_id, document_type=3, org_name=org_name)

        # Certificados de esa carátula
        certs = Polizas.objects.filter(
            caratula=policy_id,
            document_type=6,
            org_name=org_name, certificado_inciso_activo=True
        ).only('id')

        # ======= Crear BATCH =======
        batch = MassivePDFBatch.objects.create(
            policy_id=policy_id,
            org_name=org_name,
            created_by=request.user if request.user and request.user.is_authenticated else None
        )

        # ======= Construir mapa titular->cert =======
        map_name = {}
        duplicates = set()

        for c in certs:
            certificateNumber = c.certificate_number
            # Obtén titularAsegurado según ramo/subramo (tu lógica)
            if caratula.ramo and caratula.ramo.ramo_code == 1:
                form = Life.objects.filter(policy=c).select_related('personal').first()
                titularAsegurado = get_person_name(form.personal) if form else 'Sin asegurado'

            elif caratula.ramo and caratula.ramo.ramo_code == 2:
                form = AccidentsDiseases.objects.filter(policy=c).select_related('personal').first()
                titularAsegurado = get_person_name(form.personal) if form else 'Sin asegurado'

            elif caratula.subramo and caratula.subramo.subramo_code == 9:
                form = AutomobilesDamages.objects.filter(policy=c).first()
                if form:
                    titularAsegurado = (form.serial or '')
                else:
                    titularAsegurado = 'Sin asegurado'

            elif caratula.ramo and caratula.ramo.ramo_code == 3 and not (caratula.subramo and caratula.subramo.subramo_code == 9):
                form = Damages.objects.filter(policy=c).first()
                titularAsegurado = form.insured_item if form and form.insured_item else 'Sin asegurado'

            else:
                titularAsegurado = 'Sin asegurado'

            # key = normalize_name(titularAsegurado)
            key = normalize_name(certificateNumber)
            if not key:
                continue

            if key in map_name:
                duplicates.add(key)
                # map_name[key].append({'id': c.id, 'titular': titularAsegurado})
                map_name[key].append({'id': c.id, 'titular': certificateNumber,'asegurado': titularAsegurado})
            else:
                # map_name[key] = [{'id': c.id, 'titular': titularAsegurado}]
                map_name[key] = [{'id': c.id, 'titular': certificateNumber,'asegurado': titularAsegurado}]

        matched_list = []
        unmatched_list = []
        errors_list = []

        # si “nombre” viene, úsalo por índice; si no, usa f.name
        # (normalmente vendrán en el mismo orden)
        for idx, f in enumerate(files):
            try:
                filename = (names[idx] if idx < len(names) and names[idx] else f.name) or ''
                base, ext = os.path.splitext(filename)

                if ext.lower() != '.pdf':
                    unmatched_list.append({'filename': filename, 'reason': 'No es PDF'})
                    MassivePDFBatchItem.objects.create(
                        batch=batch, filename=filename, status='UNMATCHED', reason='No es PDF'
                    )
                    continue

                key = normalize_name(base)
                if not key:
                    unmatched_list.append({'filename': filename, 'reason': 'Nombre de archivo inválido'})
                    MassivePDFBatchItem.objects.create(
                        batch=batch, filename=filename, status='UNMATCHED', reason='Nombre de archivo inválido'
                    )
                    continue

                if key in duplicates:
                    unmatched_list.append({'filename': filename, 'reason': 'Coincidencia múltiple (titular duplicado)'})
                    MassivePDFBatchItem.objects.create(
                        batch=batch, filename=filename, status='UNMATCHED', reason='Coincidencia múltiple (titular duplicado)'
                    )
                    continue

                matches = map_name.get(key)
                if not matches:
                    unmatched_list.append({'filename': filename, 'reason': 'No se encontró certificado con ese titular'})
                    MassivePDFBatchItem.objects.create(
                        batch=batch, filename=filename, status='UNMATCHED', reason='No se encontró certificado con ese titular'
                    )
                    continue

                match = matches[0]
                cert_id = match['id']
                titular_ok = match['asegurado']

                cert = Polizas.objects.get(id=cert_id, document_type=6, org_name=org_name)

                # ======= GUARDAR ARCHIVO =======
                pol_file = PolizasFile(
                    owner=cert,
                    nombre=filename,
                    org_name=org_name,
                    shared=False,
                    migrated=False,
                    sensible=False
                )
                pol_file.arch.save(filename, f, save=False)
                pol_file.save()

                matched_list.append({
                    'filename': filename,
                    'certificate_id': cert.id,
                    'titular': titular_ok,
                    'polizas_file_id': pol_file.id
                })

                MassivePDFBatchItem.objects.create(
                    batch=batch,
                    filename=filename,
                    certificate_id=cert.id,
                    titular=titular_ok,
                    status='MATCHED',
                    polizas_file=pol_file
                )

            except Exception as e:
                errors_list.append({'filename': getattr(f, 'name', ''), 'reason': str(e)})
                MassivePDFBatchItem.objects.create(
                    batch=batch,
                    filename=getattr(f, 'name', ''),
                    status='ERROR',
                    reason=str(e)
                )

        summary = {
            'total': len(files),
            'matched': len(matched_list),
            'unmatched': len(unmatched_list),
            'errors': len(errors_list),
        }

        payload = {
            'summary': summary,
            'matched_list': matched_list,
            'unmatched_list': unmatched_list,
            'errors_list': errors_list,
            'batch_id': batch.id
        }

        batch.result_json = json.dumps(payload)
        batch.save()

        return Response(payload, status=status.HTTP_200_OK)
    # carga masiva
# consulta cargas masivas pdf a certificados
class MassivePDFBatchListView(APIView):
    permission_classes = (IsAuthenticatedV2, IsOrgMemberV2)

    def get(self, request, policy_id):
        org_name = request.GET.get('org')
        if not org_name:
            return Response({'detail': 'Falta org.'}, status=status.HTTP_400_BAD_REQUEST)

        qs = MassivePDFBatch.objects.filter(policy_id=policy_id, org_name=org_name).order_by('-created_at')[:50]

        data = []
        for b in qs:
            # si guardaste result_json, úsalo para resumen rápido
            summary = None
            if b.result_json:
                try:
                    summary = json.loads(b.result_json).get('summary')
                except:
                    summary = None

            # si no hay summary, calcula por items
            if not summary:
                total = b.items.count()
                matched = b.items.filter(status='MATCHED').count()
                unmatched = b.items.filter(status='UNMATCHED').count()
                errors = b.items.filter(status='ERROR').count()
                summary = {'total': total, 'matched': matched, 'unmatched': unmatched, 'errors': errors}

            data.append({
                'batch_id': b.id,
                'created_at': b.created_at,
                'created_by': getattr(b.created_by, 'username', None),
                'summary': summary
            })

        return Response({'results': data}, status=200)
# bathc item details
class MassivePDFBatchDetailView(APIView):
    permission_classes = (IsAuthenticatedV2, IsOrgMemberV2)

    def get(self, request, batch_id):
        org_name = request.GET.get('org')
        if not org_name:
            return Response({'detail': 'Falta org.'}, status=status.HTTP_400_BAD_REQUEST)

        b = MassivePDFBatch.objects.get(id=batch_id, org_name=org_name)

        items = b.items.all().order_by('id')
        matched_list = []
        unmatched_list = []
        errors_list = []

        for it in items:
            certificado = None
            if it and it.certificate_id:
                certificado = Polizas.objects.get(org_name=org_name,id=it.certificate_id, document_type=6)
            row = {
                'filename': it.filename,
                'certificate_id': it.certificate_id,
                'numerocertificado':certificado.certificate_number if certificado else '',
                'titular': it.titular,
                'reason': it.reason,
                'polizas_file_id': it.polizas_file_id
            }
            if it.status == 'MATCHED':
                matched_list.append(row)
            elif it.status == 'UNMATCHED':
                unmatched_list.append(row)
            else:
                errors_list.append(row)

        summary = {
            'total': items.count(),
            'matched': len(matched_list),
            'unmatched': len(unmatched_list),
            'errors': len(errors_list),
        }

        return Response({
            'batch_id': b.id,
            'policy_id': b.policy_id,
            'created_at': b.created_at,
            'created_by': getattr(b.created_by, 'username', None),
            'summary': summary,
            'matched_list': matched_list,
            'unmatched_list': unmatched_list,
            'errors_list': errors_list
        }, status=200)

# fin jira 859
import json
import xlwt
from django.http import HttpResponse
from .models import MassivePDFBatch
@api_view(['GET'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2))
def export_massive_pdfs_excel(request, batch_id):
    org_name = request.GET.get('org')
    if not org_name:
        return Response({'detail': 'Falta org.'}, status=status.HTTP_400_BAD_REQUEST)

    batch = MassivePDFBatch.objects.get(id=batch_id, org_name=org_name)

    qs_ok = MassivePDFBatchItem.objects.filter(batch=batch, status='MATCHED')
    qs_bad = MassivePDFBatchItem.objects.filter(batch=batch, status='UNMATCHED')

    wb = xlwt.Workbook(encoding='utf-8')

    # Hoja 1: Cargados
    ws1 = wb.add_sheet('Cargados')
    headers1 = ['Archivo', 'ID Certificado','Número de Certificado', 'Titular', 'PolizasFile ID']
    for col, h in enumerate(headers1):
        ws1.write(0, col, h)

    row = 1
    for it in qs_ok:
        certificado = None
        if it and it.certificate_id:
            certificado = Polizas.objects.get(org_name=org_name,id=it.certificate_id, document_type=6)
        ws1.write(row, 0, it.filename or '')
        ws1.write(row, 1, it.certificate_id or '')
        ws1.write(row, 2, certificado.certificate_number if certificado else '' or '')
        ws1.write(row, 3, it.titular or '')
        ws1.write(row, 4, it.polizas_file_id or '')
        row += 1

    # Hoja 2: Sin coincidencia
    ws2 = wb.add_sheet('Sin coincidencia')
    headers2 = ['Archivo', 'Motivo']
    for col, h in enumerate(headers2):
        ws2.write(0, col, h)

    row = 1
    for it in qs_bad:
        ws2.write(row, 0, it.filename or '')
        ws2.write(row, 1, it.reason or 'No corresponde a ningún certificado')
        row += 1

    response = HttpResponse(content_type='application/vnd.ms-excel')
    response['Content-Disposition'] = 'attachment; filename="resultado_pdfs_batch_%s.xls"' % batch_id
    wb.save(response)
    return response
