from copy import deepcopy
@api_view(['POST'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2))
def CopyDataRenewal(request):
    id_old_caratula = request.data['old_id']
    id_new_caratula = request.data['new_id']
    clone_certs = request.data['clone_certs']

    childs_subs = Polizas.objects.filter(caratula = id_old_caratula, document_type = 4)

    for sub in childs_subs:
        new_sub = deepcopy(sub)
        new_sub.caratula = id_new_caratula
        new_sub.pk = None
        new_sub.save()

        childs_cats = Polizas.objects.filter(caratula = id_old_caratula, document_type = 5, parent = sub)

        for cat in childs_cats:
            new_cat = deepcopy(cat)
            new_cat.caratula = id_new_caratula
            new_cat.parent = new_sub
            new_cat.pk = None
            new_cat.save()

            if int(clone_certs) == 1:
                childs_certs = Polizas.objects.filter(caratula = id_old_caratula, document_type = 6)

                for cert in childs_certs:
                    new_cert = deepcopy(cert)
                    new_cert.caratula = id_new_caratula
                    new_cert.parent = new_cat
                    new_cert.pk = None
                    new_cert.save()

                    if cert.ramo.ramo_code == 1:
                        form = Life.objects.filter(policy = cert)[0]
                        new_form = deepcopy(form)
                        new_form.pk = None
                        new_form.policy = new_cert
                        new_form.save()

                        extras = Beneficiaries.objects.filter(life = form)
                        for ext in extras:
                            new_ext = deepcopy(ext)
                            new_ext.pk = None
                            new_ext.life = new_form
                            new_ext.save()


                    elif cert.ramo.ramo_code == 2:
                        form = AccidentsDiseases.objects.filter(policy = cert)[0]
                        new_form = deepcopy(form)
                        new_form.pk = None
                        new_form.policy = new_cert
                        new_form.save()

                        extras = Relationship.objects.filter(accident = form)
                        for ext in extras:
                            new_ext = deepcopy(ext)
                            new_ext.pk = None
                            new_ext.accident = new_form
                            new_ext.save()

                    
                    elif cert.subramo.subramo_code == 9:
                        form = AutomobilesDamages.objects.filter(policy = cert)[0]
                        new_form = deepcopy(form)
                        new_form.pk = None
                        new_form.policy = new_cert
                        new_form.save()
                    
                    else:
                        form = Damages.objects.filter(policy = cert)[0]
                        new_form = deepcopy(form)
                        new_form.pk = None
                        new_form.policy = new_cert
                        new_form.save()

    paquetes = Package.objects.filter(policy = int(id_old_caratula), org_name=org_name)
    for paq in paquetes:
        new_paq = deepcopy(paq)
        new_paq.pk = None
        new_paq.policy = id_new_caratula
        new_paq.save()


    return Response(True)

