class CotizacionViewSet(viewsets.ModelViewSet):
    serializer_class = CotizacionSerializer
    permission_classes = (IsAuthenticatedV2, IsOrgMemberV2)

    def partial_update(self, request, pk=None):
        org_name = request.user.user_info.org_name
        instance = self.get_object()

        # 1) Extraemos 'aseguradora' del payload (si viene), sin dejar que DRF lo procese automáticamente
        aseguradoras_nuevas = request.data.pop('aseguradora', None)

        # 2) Actualizamos el resto de campos
        serializer = self.get_serializer(
            instance, data=request.data, partial=True
        )
        serializer.is_valid(raise_exception=True)
        serializer.save()

        # 3) Si mandaron aseguradoras, las procesamos manualmente:
        if aseguradoras_nuevas is not None:
            # Parseamos la lista (puede venir como lista de strings JSON)
            parsed = []
            for item in aseguradoras_nuevas:
                # si viene como string JSON, lo parseamos; 
                # si ya es dict, lo usamos directamente
                alias_dict = ast.literal_eval(item) if isinstance(item, str) else item
                if alias_dict and 'alias' in alias_dict:
                    parsed.append(alias_dict['alias'])

            # Creamos o recuperamos cada aseguradora nueva, sin tocar las viejas
            for alias in parsed:
                AseguradorasCotizacionPrimas.objects.get_or_create(
                    cotizacion=instance,
                    org_name=org_name,
                    aseguradora=alias
                )
            # Nota: NO hacemos ningún delete() sobre las existentes

        # 4) Devolvemos la cotización actualizada
        return Response(serializer.data, status=status.HTTP_200_OK)
