@api_view(['POST'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2, ))
def GetReportVentaCruzada(request):
    # Parameters
    notify_inactive = request.data['notifyInactiveBranches']
    polizas_del_vendedor=None
    org_name = request.GET.get('org')
    group = request.data['grupo']
    page = request.data['page']
    provider = request.data['providers']
    ramo = request.data['ramos']
    subramo = request.data['subramos']
    vendedor = request.data['vendedor']
    only_inactive = request.data['only_active']
    
    ramos_not = request.data['ramos_not']
    subramos_not = request.data['subramos_not']
    
    # Multiples aseguradoras
    if provider:
        providers = list(Provider.objects.filter(org_name = request.GET.get('org'), id__in = provider).distinct('id').values_list('pk', flat=True))
    else:
        providers = list(Provider.objects.values_list('pk', flat=True))
    if ramo:
        ramos = list(Ramos.objects.filter(org_name = request.GET.get('org'), provider__in = providers,ramo_code__in = ramo).values_list('pk', flat=True))
    else:
        ramos = list(Ramos.objects.filter(org_name = request.GET.get('org'), provider__in = providers).values_list('pk', flat=True))

    # rsubramos_sel----
    if subramo:
        subramos = list(SubRamos.objects.filter(org_name = request.GET.get('org'), ramo__in = ramos,subramo_code__in= subramo).values_list('pk', flat=True))
    else:
        subramos = list(SubRamos.objects.filter(org_name = request.GET.get('org'), ramo__in = ramos).values_list('pk', flat=True)) 
    
    # Grupo
    if int(group) > 0:
        grupos = Group.objects.get(pk= int(group), org_name = request.GET.get('org'))
    else:
        grupos = Group.objects.filter(org_name = request.GET.get('org')) #guardar el filtro para el final
    

    if not only_inactive:

        edoClientes = Polizas.objects.filter(
            org_name =  request.GET.get('org'), 
            aseguradora__in = providers,
            ramo__in = ramos, 
            subramo__in = subramos,
            status__in = [10,14],
            document_type__in = [1,3,11,12]
        ).exclude(status=0).exclude(document_type__in=[4,5,6,7,8,10])
    else:
        edoClientes = Polizas.objects.filter(
            org_name =  request.GET.get('org'), 
            aseguradora__in = providers,
            ramo__in = ramos, 
            subramo__in = subramos,
            document_type__in = [1,3,11,12]
        ).exclude(status=0).exclude(document_type__in=[4,5,6,7,8,10])
    
    if vendedor and int(vendedor) > 0:
        polizas_del_vendedor = list(ReferenciadoresInvolved.objects.filter(referenciador__id =  vendedor,is_changed=False,org_name=request.GET.get('org')).values_list('policy', flat=True))
        edoClientes = edoClientes.filter(id__in = polizas_del_vendedor)

    polizas_no_existentes = Polizas.objects.filter(
        org_name =  request.GET.get('org'), 
        status__in = [10,14],
        document_type__in = [1,3,11,12],
    ).exclude(status=0).exclude(document_type__in=[4,5,6,7,8,10])

    # print('Before')
    # print(polizas_no_existentes.distinct('ramo__ramo_name').values_list('ramo__ramo_name', flat=True))
    # print(polizas_no_existentes.distinct('subramo__subramo_name').values_list('subramo__subramo_name', flat=True))

    # print('After')
    if subramos_not and len(subramos_not) > 0:
        # print('1')
        polizas_no_existentes = polizas_no_existentes.filter(subramo__subramo_code__in = subramos_not)
    elif ramos_not and len(ramos_not) > 0:
        # print('2')
        polizas_no_existentes = polizas_no_existentes.filter(ramo__ramo_code__in = ramos_not)
    else:
        # print('3')
        polizas_no_existentes = polizas_no_existentes.filter(id = 0)
    
    
    # print(polizas_no_existentes.distinct('ramo__ramo_name').values_list('ramo__ramo_name', flat=True))
    # print(polizas_no_existentes.distinct('subramo__subramo_name').values_list('subramo__subramo_name', flat=True))
    
    
    if polizas_no_existentes.exists():
        contratantes_primarios = list(edoClientes.values_list('contractor', flat=True))
        contratantes_secundarios = []
        for a in list(edoClientes.values_list('contractor', flat=True)):
            if len(polizas_no_existentes.filter(contractor__id = a)) == 0:
                contratantes_secundarios.append(a)
            else:
                continue

        edoClientes = edoClientes.filter(contractor__id__in = contratantes_secundarios)

    contratantes_sin_polizas=[]
    if only_inactive:
        ids = []
        # agregar contraantes sin póliza alguna
        contratantes_con_polizas = Polizas.objects.filter(org_name=request.GET.get('org'),document_type__in = [1,3,11,12]).exclude(status=0).distinct('contractor__id').values_list('contractor__id', flat=True)
        for iu in contratantes_con_polizas:
            if iu:
                ids.append(int(iu))
        contratantes_sin_polizas = Contractor.objects.filter(is_active=True,org_name=request.GET.get('org')).exclude(id__in=ids)

    try:
        dataToFilter = getDataForPerfilRestricted(request, request.GET.get('org'))
    except Exception as er:
        dataToFilter = {}
    if dataToFilter:
        # Contratantes***
        polizas = Polizas.objects.filter(document_type__in = [1,3,11,12], org_name = request.GET.get('org')).exclude(status = 0)
        polizasToF = Polizas.objects.filter(document_type__in = [1,3,11], org_name = request.GET.get('org')).exclude(status = 0)
        if dataToFilter['ccpr']:
            polizasToF = polizasToF.filter(contractor__in = list(dataToFilter['ccpr']))
        if dataToFilter['cgpr']:
            polizasToF = polizasToF.filter(contractor__group__in = list(dataToFilter['cgpr']))
        if dataToFilter['ccepr']:
            polizasToF = polizasToF.filter(contractor__cellule__in = list(dataToFilter['ccepr']))
        if dataToFilter['crpr']:
            polizasToF = polizasToF.filter(contractor__vendor__in = list(dataToFilter['crpr']))
        if dataToFilter['cspr']:
            polizasToF = polizasToF.filter(contractor__sucursal__in = list(dataToFilter['cspr']))
        # Pólizas ****
        if dataToFilter['pppr']:
            polizasToF = polizasToF.filter(pk__in = list(dataToFilter['pppr']))
        if dataToFilter['pgpr']:
            polizasToF = polizasToF.filter(contractor__group__in = list(dataToFilter['pgpr']))
        if dataToFilter['pcepr']:
            polizasToF = polizasToF.filter(celula__in = list(dataToFilter['pcepr']))
        if dataToFilter['prpr']:
            polizasToF = polizasToF.filter(ref_policy__referenciador__in = list(dataToFilter['prpr']))
        if dataToFilter['pspr']:
            polizasToF = polizasToF.filter(sucursal__in = list(dataToFilter['pspr']))
        if dataToFilter['papr']:
            polizasToF = polizasToF.filter(groupinglevel__in = list(dataToFilter['papr']))
        if dataToFilter['pcapr']:
            polizasToF = polizasToF.filter(clave__in = list(dataToFilter['pcapr']))
        if dataToFilter['psrpr']:
            polizasToF = polizasToF.filter(subramo__subramo_code__in = list(dataToFilter['psrpr']))
        if dataToFilter['paspr']:
            polizasToF = polizasToF.filter(aseguradora__in = list(dataToFilter['paspr']))
        if dataToFilter['pstpr']:
            polizasToF = polizasToF.filter(status__in = list(dataToFilter['pstpr']))
        
        polizasCT = polizas.filter(document_type = 12, parent__in = list(polizasToF))
        polizasFin = list(polizasToF.values_list('pk', flat = True)) + list(polizasCT.values_list('pk', flat = True))
        
        try:
            edoClientes = edoClientes.filter(pk__in = list(polizasFin))
            edoClientes_all = edoClientes_all.filter(pk__in = list(polizasFin))
        except Exception as e:
            pass
    clientes = Contractor.objects.filter(id__in = list(edoClientes.values_list('contractor', flat=True)), group = grupos,org_name=request.GET.get('org'),is_active=True)
    if contratantes_sin_polizas:
        solo_clientes=Contractor.objects.filter(id__in = contratantes_sin_polizas,is_active=True)
        clientes = clientes | solo_clientes
    if vendedor and int(vendedor) > 0:
        polizas_del_vendedor = list(ReferenciadoresInvolved.objects.filter(referenciador__id =  vendedor,is_changed=False,org_name=request.GET.get('org')).values_list('policy', flat=True))
        get_contractor_vendedor=Polizas.objects.filter(org_name=request.GET.get('org'),document_type__in = [1,3,11,12],id__in=polizas_del_vendedor).exclude(status=0)
        clientes = clientes.filter(id__in=get_contractor_vendedor.values_list('contractor__id',flat=True), is_active=True)
    data_final = []

    paginator = Paginator(clientes, 10)
    try:
        page = request.data['page']
        results = paginator.page(page)
    except:
        results = paginator.page(1)
    serializer = ContractorVCSerializer(results, context = {'request':request}, many = True)
    # return Response(serializer.data)
    # construir respuesta tipo paginada DRF
    response_data = {
        'count': paginator.count,
        'next': results.next_page_number() if results.has_next() else None,
        'previous': results.previous_page_number() if results.has_previous() else None,
        'results': serializer.data,
        'data_final':data_final if notify_inactive else []
    }

    return Response(response_data)



    

