        ws.write(row_num, 33, 'Baja' if row.baja else '', font_style)   
        ws.write(row_num, 34, row.motivo_baja if row.baja and row.motivo_baja else '', font_style)   

        # ─── Adjuntos (usar .count() para no traer todos los objetos) ───────
        adjuntos_count = ContractorFile.objects.filter(owner=row, org_name=row.org_name).count()
        ws.write(row_num, 35, adjuntos_count if adjuntos_count else 'Sin adjuntos', font_style)

