def checkStatusReceipt(request):
    switcher = {
        1: "Pagado",
        2: "Cancelado",
        3: "Prorrogado",
        4: "Pendiente de pago",
        5: "Liquidado",
        6: "Conciliado",
        7: "Cerrado"
    }
    return switcher.get(request, "Invalid status")

