# ----------------Fianza Colectiva Nueva-----------
class FianzasCollectViewSet(viewsets.ModelViewSet):
    serializer_class = FianzaCollectiveHyperSerializer
    permission_classes = (IsAuthenticatedV2, IsOrgMemberV2 )
    def perform_create(self, serializer):
        def create_intern_number(obj):
            internal_number = 'OT' + '%07d' % obj.id
            obj.internal_number = internal_number
            obj.save()
        obj = serializer.save(owner=self.request.user, org_name = self.request.GET.get('org'))
        if obj.id:
            if obj.poliza_number:
                send_log(self.request.user, self.request.GET.get('org'), 'POST', 13, '%s' % 'creó la Póliza Colectividad de Fianza (colectiva) ' + obj.poliza_number, obj.id)
            else:
               send_log(self.request.user, self.request.GET.get('org'), 'POST', 13, '%s' % 'creó el Proyecto Colectividad de Fianza (colectiva) ', obj.id)
        create_intern_number(obj)

    def get_queryset(self):
        return custom_get_queryset(self.request, Polizas)
