@api_view(['POST'])
@pm((IsAuthenticatedV2, ))
def CertificatesCollsuretyViewSet(request):
    certificados = []
    try:    
        collSurety = Polizas.objects.get(pk = request.data[0]['caratula'], document_type = 8, org_name = request.GET.get('org'))
    except Polizas.DoesNotExist:
        return Response(status=status.HTTP_404_NOT_FOUND, data = 'No se encontró la Colectividad de Fianza')
    except Polizas.MultipleObjectsReturned:
        collSurety = Polizas.objects.filter(pk = request.data[0]['caratula'], document_type = 8, org_name = request.GET.get('org')).exclude(status = 0).latest('id')
    for a in request.data:
        cont = 0
        for b in request.data:
            if (str(a['certificate_number']) == str(b['certificate_number'])) and (str(a['parent']) == str(b['parent'])):
                cont += 1
        if cont >1:
            return Response(status=400, data = 'El certificado: '+str(a['certificate_number'])+', esta repetido en la Categoría de la Fianza Colectiva')
        try:    
            certificateExist = Polizas.objects.get(parent__id = a['parent'],caratula = str(request.data[0]['caratula']), certificate_number = str(a['certificate_number']), document_type = 10, certificado_inciso_activo = True, org_name = request.GET.get('org'))
            if certificateExist:
                return Response(status=400, data = 'El certificado: '+str(a['certificate_number'])+', ya existe dentro de la Categoría de la Fianza Colectiva')
        except Exception as erc:
            pass
    for a in request.data:
        beneficiarie = a.pop('beneficiaries_poliza')
        beneficiarie.pop('certificate_number')
        contract = a.pop('contract_poliza')
        try:    
            categoryCollectiveSurety = Polizas.objects.get(pk = a['parent'], document_type = 9, org_name = request.GET.get('org'))
        except Polizas.DoesNotExist:
            return Response(status=status.HTTP_404_NOT_FOUND, data = 'No se encontró la Categoría de la Colectividad de Fianza')
        except Polizas.MultipleObjectsReturned:
            categoryCollectiveSurety = Polizas.objects.filter(pk = a['parent'], document_type = 9, org_name = request.GET.get('org')).exclude(status = 0).latest('id')
        try:    
            collectiveSurety = Polizas.objects.get(pk = a['caratula'], document_type = 8, org_name = request.GET.get('org'))
        except Polizas.DoesNotExist:
            return Response(status=status.HTTP_404_NOT_FOUND, data = 'No se encontró la Colectividad de Fianza')
        except Polizas.MultipleObjectsReturned:
            collectiveSurety = Polizas.objects.filter(pk = a['caratula'], document_type = 8, org_name = request.GET.get('org')).exclude(status = 0).latest('id')

        certificado = Polizas(
            observations = a['observations'], 
            parent = categoryCollectiveSurety,
            caratula = a['caratula'],
            certificate_number = a['certificate_number'],
            poliza_number = a['poliza_number'],
            org_name = categoryCollectiveSurety.org_name,
            owner = categoryCollectiveSurety.owner,
            contractor = categoryCollectiveSurety.contractor,
            aseguradora = categoryCollectiveSurety.aseguradora,
            ramo = categoryCollectiveSurety.ramo,
            subramo = categoryCollectiveSurety.subramo,
            clave = categoryCollectiveSurety.clave,
            address = categoryCollectiveSurety.address,
            start_of_validity = categoryCollectiveSurety.start_of_validity,
            end_of_validity = categoryCollectiveSurety.end_of_validity,
            document_type = 10,            
            )
        certificado.save()
        if beneficiarie['first_name']:
            beneficiarie['full_name'] = beneficiarie['first_name']+' '+beneficiarie['last_name'] +' '+beneficiarie['second_last_name']
        else:
            beneficiarie['full_name'] = ''

        titular = BeneficiariesContract.objects.create(owner = categoryCollectiveSurety.owner, org_name= categoryCollectiveSurety.org_name, poliza = certificado, **beneficiarie)
        contract = Contract.objects.create(poliza = certificado, owner = certificado.owner, org_name = certificado.org_name, **contract)
        certificados.append(certificado.id)
    certificates1 = Polizas.objects.filter(pk__in = certificados, org_name = request.GET.get('org'))
    serializer = PolizaInfoSerializer(certificates1, context = {'request':request}, many = True)
    if collSurety.id:
        if collSurety.poliza_number:
            send_log(request.user, request.GET.get('org'), 'POST', 13, '%s' % 'creo un total de certificados de: '+str(len(request.data))+' en la Colectividad de Fianza ' + collSurety.poliza_number, collSurety.id)
        else:
           send_log(request.user, request.GET.get('org'), 'POST', 13, '%s' % 'creo un total de certificados de: '+str(len(request.data))+' en el Proyecto Colectivo de Fianza ',collSurety.id)
       
    return JsonResponse({'status': 'created', 'id': certificados, 'data': serializer.data})
