@api_view(['POST'])
@pm((IsAuthenticatedV2, ))
def updateReceiptsCollective(request):    
    recibosCertificado = Recibos.objects.filter(receipt_type = 5, status = 1, poliza__caratula = str(request.data['caratula']), isActive = True, pay_form = None).order_by('org') 
    recibosPoliza = Recibos.objects.filter(poliza__id = request.data['caratula'], receipt_type = 1, org_name = request.GET.get('org'), status__in = [4], isActive = True).order_by('recibo_numero')
    try:    
        colectividad = Polizas.objects.get(pk = request.data['caratula'], receipts_by = 3, document_type = 3, org_name = request.GET.get('org'))
    except Polizas.DoesNotExist:
        return Response(status=status.HTTP_404_NOT_FOUND, data = 'No se encontró la Colectividad')
    except Polizas.MultipleObjectsReturned:
        colectividad = Polizas.objects.filter(pk = request.data['caratula'], receipts_by = 3, document_type = 3, org_name = request.GET.get('org')).exclude(status = 0).latest('id')
    if int(request.data['option']) == 1:
        try:
            sum_p_total = recibosCertificado.values('org').annotate(Sum('prima_total'))
            if float(sum_p_total[0]['prima_total__sum']) >= float(recibosPoliza[0].prima_total):
                recibosPoliza[0].status = 1
                recibosPoliza[0].save()
                reciboUpdated = Recibos.objects.get(pk = int(recibosPoliza[0].id))
                reciboUpdated.status = 1
                reciboUpdated.save()
                for xyz in recibosCertificado:
                    xyz.pay_form = 1
                    xyz.save()

        except Exception as ers:
            pass
    elif int(request.data['option']) == 2:
        try:
            ptCertificados = Polizas.objects.filter(caratula = str(colectividad.id), document_type = 6, certificado_inciso_activo = True).order_by('caratula')            
            pneta = ptCertificados.values('org').annotate(Sum('p_neta'))
            ptotal = ptCertificados.values('org').annotate(Sum('p_total'))
            rpf = ptCertificados.values('org').annotate(Sum('rpf'))
            derecho = ptCertificados.values('org').annotate(Sum('derecho'))
            iva = ptCertificados.values('org').annotate(Sum('iva'))
            comision = ptCertificados.values('org').annotate(Sum('comision'))
            sub_total = float(pneta[0]['p_neta__sum'])+float(derecho[0]['derecho__sum'])+float(rpf[0]['rpf__sum'])
            # --------------
            recibosColectividad = Recibos.objects.filter(receipt_type = 1, status = 4, poliza__id = int(request.data['caratula']), isActive = True).order_by('poliza__id')            
            primaTotalCol = recibosColectividad.values('poliza').annotate(Sum('prima_total'))
            primaNetaCol = recibosColectividad.values('poliza').annotate(Sum('prima_neta'))
            ivaCol = recibosColectividad.values('poliza').annotate(Sum('iva'))
            comisionCol = recibosColectividad.values('poliza').annotate(Sum('comision'))
            rpfCol = recibosColectividad.values('poliza').annotate(Sum('rpf'))
            derechoCol = recibosColectividad.values('poliza').annotate(Sum('derecho'))
            subCol = recibosColectividad.values('poliza').annotate(Sum('sub_total'))
            if float(ptotal[0]['p_total__sum']) > float(primaTotalCol[0]['prima_total__sum']):
                restoPT = float(ptotal[0]['p_total__sum']) - float(primaTotalCol[0]['prima_total__sum'])
                restoPN = float(pneta[0]['p_neta__sum']) - float(primaNetaCol[0]['prima_neta__sum'])
                restoIva = float(iva[0]['iva__sum']) - float(ivaCol[0]['iva__sum'])
                restoRpf = float(rpf[0]['rpf__sum']) - float(rpfCol[0]['rpf__sum'])
                restoDerecho = float(derecho[0]['derecho__sum']) - float(derechoCol[0]['derecho__sum'])
                restoComision = float(comision[0]['comision__sum']) - float(comisionCol[0]['comision__sum'])
                restoSub = float(sub_total) - float(subCol[0]['sub_total__sum'])
                for xy in recibosColectividad:
                    prima_total = float(xy.prima_total) + ((float(restoPT)/len(recibosColectividad)))
                    prima_neta = float(xy.prima_neta) + ((float(restoPN)/len(recibosColectividad)))
                    iva_fin = float(xy.iva) + ((float(restoIva)/len(recibosColectividad)))
                    rpf_fin = float(xy.rpf) + ((float(restoRpf)/len(recibosColectividad)))
                    derecho_fin = float(xy.derecho) + ((float(restoDerecho)/len(recibosColectividad)))
                    comision_fin = float(xy.comision) + ((float(restoComision)/len(recibosColectividad)))
                    subtotal = float(xy.sub_total) + ((float(restoSub)/len(recibosColectividad)))
                    xy.prima_total = prima_total
                    xy.prima_neta = prima_neta
                    xy.comision = comision_fin
                    xy.rpf = rpf_fin
                    xy.derecho = derecho_fin
                    xy.iva = iva_fin
                    xy.sub_total = subtotal
                    xy.save()

                colectividad.sub_total = sub_total
                colectividad.p_total = float(ptotal[0]['p_total__sum'])
                colectividad.p_neta = float(pneta[0]['p_neta__sum'])
                colectividad.rpf = float(rpf[0]['rpf__sum'])
                colectividad.derecho = float(derecho[0]['derecho__sum'])
                colectividad.iva = float(iva[0]['iva__sum'])
                colectividad.comision = float(comision[0]['comision__sum'])
                colectividad.save()
        except Exception as ers:
            pass
    elif int(request.data['option']) == 3:
        try:
            ptCertificados = Polizas.objects.filter(caratula = str(colectividad.id), document_type = 6, certificado_inciso_activo = True).order_by('caratula')            
            pneta = ptCertificados.values('org').annotate(Sum('p_neta'))
            ptotal = ptCertificados.values('org').annotate(Sum('p_total'))
            rpf = ptCertificados.values('org').annotate(Sum('rpf'))
            derecho = ptCertificados.values('org').annotate(Sum('derecho'))
            iva = ptCertificados.values('org').annotate(Sum('iva'))
            comision = ptCertificados.values('org').annotate(Sum('comision'))
            sub_total = float(pneta[0]['p_neta__sum'])+float(derecho[0]['derecho__sum'])+float(rpf[0]['rpf__sum'])
            # --------------
            recibosColectividad = Recibos.objects.filter(receipt_type = 1, status = 4, poliza__id = int(request.data['caratula']), isActive = True).order_by('poliza__id')            
            primaTotalCol = recibosColectividad.values('poliza').annotate(Sum('prima_total'))
            primaNetaCol = recibosColectividad.values('poliza').annotate(Sum('prima_neta'))
            ivaCol = recibosColectividad.values('poliza').annotate(Sum('iva'))
            comisionCol = recibosColectividad.values('poliza').annotate(Sum('comision'))
            rpfCol = recibosColectividad.values('poliza').annotate(Sum('rpf'))
            derechoCol = recibosColectividad.values('poliza').annotate(Sum('derecho'))
            subCol = recibosColectividad.values('poliza').annotate(Sum('sub_total'))

            if float(ptotal[0]['p_total__sum']) < float(primaTotalCol[0]['prima_total__sum']):
                restoPT = float(primaTotalCol[0]['prima_total__sum']) - float(ptotal[0]['p_total__sum'])
                restoPN = float(primaNetaCol[0]['prima_neta__sum']) - float(pneta[0]['p_neta__sum'])
                restoIva = float(ivaCol[0]['iva__sum']) - float(iva[0]['iva__sum'])
                restoRpf = float(rpfCol[0]['rpf__sum'])- float(rpf[0]['rpf__sum']) 
                restoDerecho = float(derechoCol[0]['derecho__sum']) - float(derecho[0]['derecho__sum']) 
                restoComision = float(comisionCol[0]['comision__sum']) - float(comision[0]['comision__sum'])
                restoSub = float(subCol[0]['sub_total__sum']) - float(sub_total)
                for xy in recibosColectividad:
                    subtotal = ((float(restoSub))/len(recibosColectividad))
                    prima_total = ((float(restoPT))/len(recibosColectividad))
                    prima_neta = ((float(restoPN))/len(recibosColectividad))
                    iva_fin = ((float(restoIva))/len(recibosColectividad))
                    rpf_fin = ((float(restoRpf))/len(recibosColectividad))
                    derecho_fin = ((float(restoDerecho))/len(recibosColectividad))
                    comision_fin = ((float(restoComision))/len(recibosColectividad))
                    xy.prima_total = prima_total
                    xy.prima_neta = prima_neta
                    xy.comision = comision_fin
                    xy.rpf = rpf_fin
                    xy.derecho = derecho_fin
                    xy.iva = iva_fin
                    xy.sub_total = subtotal
                    xy.save()

                colectividad.sub_total = sub_total
                colectividad.p_total = float(ptotal[0]['p_total__sum'])
                colectividad.p_neta = float(pneta[0]['p_neta__sum'])
                colectividad.rpf = float(rpf[0]['rpf__sum'])
                colectividad.derecho = float(derecho[0]['derecho__sum'])
                colectividad.iva = float(iva[0]['iva__sum'])
                colectividad.comision = float(comision[0]['comision__sum'])
                colectividad.save()

        except Exception as ers:
            pass
    else:
        pass
    # certificatesData = Polizas.objects.filter(pk__in = certificados, org_name = request.GET.get('org')) 
