@api_view(['POST'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2))
def CancelCaratulaPolizasManual(request):
    try:
        poliza = Polizas.objects.get(pk = int(request.data['id']), document_type = int(request.data['document_type']))
    except:
        if int(request.data['document_type']) ==11:
            return Response({'error':'No existe la Carátula'})
        elif (request.data['document_type'])  ==12:
            return Response({'error':'No existe la Póliza de Carátula'})
    org_name = request.GET.get('org')
    # PATCH cancelar carátula
    poliza.status = 11
    poliza.save()
    recibos = Recibos.objects.filter(poliza = poliza, org_name = org_name, status__in = [4]).exclude(receipt_type = 3)
    for r in recibos:
        r.status = 2
        r.save()
    if int(request.data['document_type']) == 11:
        polizas = Polizas.objects.filter(parent = poliza, org_name = org_name, document_type = 12)
        for pl in polizas:
            pl.status = 11
            pl.save()        
            recibosP = Recibos.objects.filter(poliza = pl, org_name = org_name, status__in = [4]).exclude(receipt_type = 3)
            for r0 in recibosP:
                r0.status = 2
                r0.save()      
            endososP = Endorsement.objects.filter(policy = pl, org_name = org_name).exclude(status = 2)
            for r1 in endososP:
                r1.status = 4
                r1.save()
    elif int(request.data['document_type']) == 12:
        recibosP = Recibos.objects.filter(poliza = poliza, org_name = org_name, status__in = [4]).exclude(receipt_type = 3)
        for r0 in recibosP:
            r0.status = 2
            r0.save()  
        if 'cancelnotas' in request.data and request.data['cancelnotas']:   
            print('.s.sssss',request.data['cancelnotas'])            
            recibosPc = Recibos.objects.filter(poliza = poliza, org_name = org_name, status__in = [4], receipt_type=3)
            for r0 in recibosPc:
                r0.status = 2
                r0.save()   
        endososP = Endorsement.objects.filter(policy = poliza, org_name = org_name).exclude(status = 2)
        for r1 in endososP:
            r1.status = 4
            r1.save()
    serializer = GetCaratulaSerializer(poliza, context = {'request': request}, many = False)
    return Response(serializer.data)

@api_view(['POST'])
@pm((IsAuthenticatedV2, ))
def CollectsForSearchViewSet(request):
    word = request.data['word']
    polizas = []
    words = []
    words = word.split()
       
    contractor = Contractor.objects.filter(reduce(and_, [Q(full_name__icontains=q) for q in words])).filter(org_name=request.GET.get('org'))
    if contractor:
        pols = Polizas.objects.filter(document_type__in = list([11]), contractor = contractor, org_name=request.GET.get('org')).exclude(status = 0)
        for pol in pols:
            if(pol.status == 10 or pol.status == 12 or pol.status == 14 ):
                polizas.append(pol)
    
    policies = Polizas.objects.filter(document_type = 11, poliza_number__icontains = word, org_name=request.GET.get('org')) 
    if policies:
        for p in policies:
            if(p.status == 10 or p.status == 12 or p.status == 14 ):
                polizas.append(p)
                
    certificados = Polizas.objects.filter(document_type =11, poliza_number__icontains = word, org_name=request.GET.get('org')).exclude(status = 0)
    try:
        dataToFilter = getDataForPerfilRestricted(request, request.GET.get('org'))
    except Exception as er:
        dataToFilter = {}
    if dataToFilter:
        # Contratantes***
        if dataToFilter['ccpr']:
            certificados = certificados.filter(contractor__in = list(dataToFilter['ccpr']))
        if dataToFilter['cgpr']:
            certificados = certificados.filter(contractor__group__in = list(dataToFilter['cgpr']))
        if dataToFilter['ccepr']:
            certificados = certificados.filter(contractor__cellule__in = list(dataToFilter['ccepr']))
        if dataToFilter['crpr']:
            certificados = certificados.filter(contractor__vendor__in = list(dataToFilter['crpr']))
        if dataToFilter['cspr']:
            certificados = certificados.filter(contractor__sucursal__in = list(dataToFilter['cspr']))
        # Pólizas ****
        if dataToFilter['pppr']:
            certificados = certificados.filter(pk__in = list(dataToFilter['pppr']))
        if dataToFilter['pgpr']:
            certificados = certificados.filter(contractor__group__in = list(dataToFilter['pgpr']))
        if dataToFilter['pcepr']:
            certificados = certificados.filter(celula__in = list(dataToFilter['pcepr']))
        if dataToFilter['prpr']:
            certificados = certificados.filter(ref_policy__referenciador__in = list(dataToFilter['prpr']))
        if dataToFilter['pspr']:
            certificados = certificados.filter(sucursal__in = list(dataToFilter['pspr']))
        if dataToFilter['papr']:
            certificados = certificados.filter(groupinglevel__in = list(dataToFilter['papr']))
        if dataToFilter['pcapr']:
            certificados = certificados.filter(clave__in = list(dataToFilter['pcapr']))
        if dataToFilter['psrpr']:
            certificados = certificados.filter(subramo__subramo_code__in = list(dataToFilter['psrpr']))
        if dataToFilter['paspr']:
            certificados = certificados.filter(aseguradora__in = list(dataToFilter['paspr']))
        if dataToFilter['pstpr']:
            certificados = certificados.filter(status__in = list(dataToFilter['pstpr']))
    if certificados:
        for c in certificados:
            polizas.append(c)

    polizas = list(set(polizas)) 
    serializer = PolizaCaratulaResumeInfoSerializer(polizas, context={'request': request}, many=True)
    return Response(serializer.data)


@api_view(['GET'])
@permission_classes((IsAuthenticatedV2,  RenovacionesReportesPermissionsV2, IsOrgMemberV2)) 
def ReporteCertificadosExcel(request):
    num_certificado = request.GET.get('num_certificado')
    num_poliza = request.GET.get('num_poliza')
    # select_provider = request.GET.get('select_provider')
    select_provider = request.GET.getlist('select_provider')
    select_ramo = request.GET.getlist('select_ramo')
    select_sramo = request.GET.getlist('select_sramo')
    select_user = request.GET.getlist('select_user')
    celula = request.GET.get('celula')
    status_cert = request.GET.get('status_cert')
    vendedor = request.GET.get('vendedor')
    status_ren_cert = request.GET.get('status_ren_cert')
    since = request.GET.get('since')
    until = request.GET.get('until')
    date_filter_by = int(request.GET.get('date_filter_by'))
    org = request.GET.get('org')
    email = request.GET.get('email')
    contratante = int(request.GET.get('contratante',0))
    observaciones = request.GET.get('observaciones')
    contributory = request.GET.get('contributory',0)
    
    # *******
    if not email:
        email = request.user.email
    
    permiso_correos = False
    if request.user.is_superuser:
        permiso_correos = True
    session = Session.objects.get(username= request.user.username)
    pmscg = session.permissions['SAAM']['Pólizas']
    for pm in pmscg:
        if pm['name'] == 'Ver correo electrónico de asegurados':
            if pm['checked'] == True:
                permiso_correos = True

    
    vendedor = request.GET.get('vendedor')
    order = request.GET.get('order')
    report_by = request.GET.get('report_by')
    try:
        ui = UserInfo.objects.get(user= request.user)
        perfil = None
        try:
            if ui.perfil_restringido:
                perfil = PerfilUsuarioRestringido.objects.get(pk = ui.perfil_restringido.id)
            else:
                perfil = None
        except Exception as ert:
            perfil = None
    except Exception as er:
        perfil = None
    payload = {
        "num_certificado": num_certificado,
        "num_poliza": num_poliza,
        "select_provider": select_provider,
        "select_ramo": select_ramo,
        "select_sramo": select_sramo,
        "select_user": select_user,
        "celula": celula,
        "status_cert": status_cert,
        "status_ren_cert": status_ren_cert,
        "since": since,
        "until": until,
        "date_filter_by": date_filter_by,
        "contributory": contributory,
        "observaciones": observaciones,
        "vendedor": vendedor,
        "order": order,
        "report_by": report_by,
        "org": request.GET.get('org'),
        'email': email,
        'contratante': contratante,
        'user':perfil.id if perfil else None,
        'Authorization': request.META['HTTP_AUTHORIZATION'],
        'permiso_correos': permiso_correos
    }
    if request.GET.get('org') == 'ancora':
        url = settings.SERVICEEXCEL_ANCORA_URL
    else:
        url = settings.SERVICEEXCEL_2_URL
    r = requests.post(url + 'certificados/', headers={'Authorization': request.META['HTTP_AUTHORIZATION']}, data = payload, stream=True)
    return Response(r.text, status = r.status_code)


