@api_view(['POST'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2))
def savepolizasmasivasflotilla(request):
    #import pdb; pdb.set_trace()
    data = request.data
    org_name = request.GET.get('org')
    results = {}
