    owner = request.user
    for r in request.data:
        ref_policy = r['ref_policy']
        try:
            if r['status'] != 1 and r['status'] !=2:
                if r['poliza_number'] == None or not r['poliza_number']:
                    return JsonResponse({'data': 'Debe agregar un Número de Póliza'})
            if r['identifier'] == None or not r['identifier']:
                    return JsonResponse({'data': 'Debe agregar un Identificador de Póliza'})
            if r['forma_de_pago'] == None or not r['forma_de_pago']:
                    return JsonResponse({'data': 'Debe agregar una Forma de Pago'})
        except Exception as ee:
            pass
        try:
            if r['contractor'] == None:
                return JsonResponse({'data':'Debe agregar un Contratante'}, status = 400)
        except Exception as er:
            return JsonResponse({'data':'Debe agregar un Contratante'}, status = 400)
        
        try:
            ref_policy = r['ref_policy']
        except Exception as er_vend:   
            ref_policy = r['ref_policy']     
        try:
            r['sucursal'] = Sucursales.objects.get(pk = r['sucursal'],org_name = request.GET.get('org'))
        except Exception as er_suc:
            r['sucursal'] = None
        try:
            r['contractor'] = Contractor.objects.get(pk = r['contractor'],org_name = request.GET.get('org'))
        except Exception as er_suc:
            r['contractor'] = None
        try:
            r['ramo'] = Ramos.objects.get(pk = r['ramo'],org_name = request.GET.get('org'))
        except Exception as er_suc:
            return JsonResponse({'data':'Debe agregar un Ramo'}, status = 400)
        if 'groupinglevel' in r:
            try:
                GroupingLevel.objects.get(pk = r['groupinglevel'],org_name = request.GET.get('org'))
            except Exception as er_suc:
                return JsonResponse({'data':'Debe agregar una Agrupación válida'}, status = 400)
        if 'celula' in r:
            try:
                CelulaContractor.objects.get(pk = r['celula'],org_name = request.GET.get('org'))
            except Exception as er_suc:
                return JsonResponse({'data':'Debe agregar una Célula válida'}, status = 400)
        try:
            r['subramo'] = SubRamos.objects.get(pk = r['subramo'],org_name = request.GET.get('org'))
        except Exception as er_suc:
            return JsonResponse({'data':'Debe agregar un Subramo'}, status = 400)
        try:
            r['aseguradora'] = Provider.objects.get(pk = r['aseguradora'],org_name = request.GET.get('org'))
        except Exception as er_suc:
            return JsonResponse({'data':'Debe agregar una Aseguradora'}, status = 400)
        try:
            r['address'] = Address.objects.get(pk = r['address'],org_name = request.GET.get('org'))
        except Exception as er_suc:
            return JsonResponse({'data':'Debe agregar un Dirección'}, status = 400)
        try:
            r['clave'] = Claves.objects.get(pk = r['clave'],org_name = request.GET.get('org'))
        except Exception as er_suc:
            return JsonResponse({'data':'Debe agregar un Clave'}, status = 400)
        try:
            r['responsable'] = User.objects.get(pk = r['responsable'])
        except Exception as er_suc:
            r['responsable'] = None
        try:
            r['collection_executive'] = User.objects.get(pk = r['collection_executive'])
        except Exception as er_suc:
            r['collection_executive'] = None
            
    for r in request.data:
        ref_policy = r['ref_policy']    
        try:
            r.pop('ref_policy')
        except Exception as er_vend:   
            ref_policy = r['ref_policy']    

        # For LOOG
        regs = []       
        try:
            celula = r.pop('celula') if 'celula' in r else 0
            groupinglevel = r.pop('groupinglevel') if 'groupinglevel' in r else 0
            polizaante = r.pop('poliza_anterior') if 'poliza_anterior' in r else ''
            celula = CelulaContractor.objects.get(id = int(celula)) if int(celula) != 0 else None
            groupinglevel = GroupingLevel.objects.get(id = int(groupinglevel)) if int(groupinglevel) != 0 else None
            flotillacaratula = Polizas.objects.create(owner = owner, org_name = request.GET.get('org'), celula = celula, groupinglevel = groupinglevel,  **r)       
            if flotillacaratula.id:
                send_log(request.user, request.GET.get('org'), 'POST', 18, '%s' % str(' creo la póliza de grupo: ')+flotillacaratula.identifier if flotillacaratula.identifier else flotillacaratula.poliza_number, flotillacaratula.id)  
                if polizaante:
                    try:
                        poliza_anterior = Polizas.objects.get(pk = polizaante, org_name = request.GET.get('org'))
                        old_policie, old_policie_created = OldPolicies.objects.get_or_create(
                            base_policy = poliza_anterior,
                            new_policy = flotillacaratula,
                            org_name = poliza_anterior.org_name,
                            owner = poliza_anterior.owner
                        )
                        poliza_anterior.status = 12
                        poliza_anterior.renewed_status = 1
                        poliza_anterior.save()
                    except Exception as es:
                        print('no poliza ante',es)
            try:
                if ref_policy:
                    for ri in ref_policy:
                        referenciado = User.objects.get(pk = ri['referenciador'])
                        referenciadors = ReferenciadoresInvolved.objects.create(org_name = request.GET.get('org'), referenciador = referenciado,policy = flotillacaratula,comision_vendedor = ri['comision_vendedor'])
                else:
                    pass
            except Exception as eri:
                pass
            # LOG fin
            try:
                serializer = GetCaratulaFullSerializer(flotillacaratula, context={'request': request}, many = False)                
                results['flotillacaratula'].append(serializer.data)
                #return JsonResponse({'data': results})
            except Exception as error_ser:
                polizaFin = Polizas.objects.get(pk = flotillacaratula.id, org_name = request.GET.get('org'))
                serializer = GetCaratulaFullSerializer(polizaFin, context={'request': request}, many = False)                
                results['flotillacaratula'].append(serializer.data)
        except Exception as e:
            print('=error flotillacaratula---',e)
            return Response(str(e)) 
    
    return JsonResponse({'data': results})
