def ReferenciadorObligatorioPermissionsV2(request,user):    
    if request.method == 'POST' or request.method == 'GET' or request.method == 'PATCH':
        token  = request.META['HTTP_AUTHORIZATION'].replace('Bearer ', '')
        session_obj = Session.objects.get(jwt_token=token)
        permissions = session_obj.permissions['SAAM']
        for permission in permissions['Referenciadores']:
            if permission['name']=='Referenciador no obligatorio' and permission['checked']:
                return True#no obligatorio
        return False #obligatorio

