@api_view(['POST'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2))
def readFileToUpPolizas(request):
    data = request.data
    org_name = request.GET.get('org')
    results = []
    owner = request.user
    polizas = request.data['polizas']
    dependientes = request.data['dependientes']
    all_policies = []
    numeros_poliza = []
    for a in polizas:
        polizas_data = {}
        polizas_data['accident'] = {}
        polizas_data['accident']['personal'] = {}
        polizas_data['accident']['relationships'] = []
        polizas_data['recibos_poliza'] = [] 
        if int(a['CLASE']) == 1:#PÓLIZA
            try:
                f = "%d/%m/%Y"        
                ainicio = datetime.strptime(a['VIGENCIA_INICIO'] , f)
                afin = datetime.strptime(a['VIGENCIA_FIN'] , f)
            except:
                f = "%m/%d/%Y"        
                ainicio = datetime.strptime(a['VIGENCIA_INICIO'] , f)
                afin = datetime.strptime(a['VIGENCIA_FIN'] , f)
            if a['NO_POLIZA'] not in numeros_poliza:
                numeros_poliza.append(a['NO_POLIZA'])
            else:
                return JsonResponse({'data': 'Existen números de Póliza repetidos -->'+str(a['NO_POLIZA'])}, status = 400)
            try:    
                polizaExistente = Polizas.objects.filter(poliza_number = a['NO_POLIZA'], document_type = 1, org_name = org_name, start_of_validity = ainicio, status = 14)
                if polizaExistente.exists():
                    return JsonResponse({'data': 'La Póliza ya existe --> ' +str(a['NO_POLIZA'])}, status = 400) 
            except Polizas.DoesNotExist:
                print('conitinua',a['NO_POLIZA'])
