            coveragesPolicy['priority'] = 1
            coveragesPolicy['package'] = polizaInd.paquete
            coveragesPolicy['coinsurance'] = polizaInd.paquete.package_name
            coveragesPolicy['coverage_name'] = polizaInd.paquete.package_name
            coveragesPolicy['deductible'] = polizaInd.paquete.package_name
