    if contractor:
        pols = Polizas.objects.filter(document_type__in = [1,12], contractor = contractor, org_name=org_name).exclude(status=0).filter(subramo__subramo_code=9)
        for pol in pols:
            if(pol.status == 10 or pol.status == 12 or pol.status == 14 or pol.status == 13 or pol.status == 11):
                if not pol in polizas:
                    polizas.append(pol.id)
    
