    if policies:
        for p in policies:
            if(p.status == 10 or p.status == 12 or p.status == 14 or p.status == 13 or p.status == 11):
                if not p in polizas:
                    polizas.append(p.id)


    policies = Polizas.objects.filter(document_type__in = [1, 12], poliza_number = word, org_name=org_name ).exclude(status=0).filter(subramo__subramo_code=9)

