# Save pólizas individuales
@api_view(['POST'])
@permission_classes((IsAuthenticatedV2, IsOrgMemberV2))
def savepolizasmasivasnorenovacionid(request):
    #import pdb; pdb.set_trace()
    data = request.data
    org_name = request.GET.get('org')
    results = []
    owner = request.user
    numeros_poliza = []    
    ui = UserInfo.objects.get(user__username= request.user)
    for r in request.data:
        # if r['id'] not in numeros_poliza:
        #     numeros_poliza.append(r['id'])
        # else:
        #     return JsonResponse({'data': 'Existen números de Póliza repetidos -->'+str(r['poliza_number'])}, status = 400)
        try:    
            polizaExistente = Polizas.objects.filter(id = r['id'], document_type__in = [1,11,3,12], org_name = request.GET.get('org')).exclude(status__in=[0,12])
            if polizaExistente.exists():
                print({'data': 'La Póliza existe --> ' +str(r['id'])}) 
            else:
                return JsonResponse({'data': 'La Póliza No existe --> ' +str(r['id'])}, status = 400) 

        except Polizas.DoesNotExist:
            return JsonResponse({'data': 'La Póliza No existe --> ' +str(r['id'])}, status = 400) 
            
    for r in request.data: 
        poliza_upd = Polizas.objects.filter(id = r['id'], document_type__in = [1,11,3,12], org_name = request.GET.get('org')).exclude(status__in=[0,12]).update(status=15,reason_ren=r['reason'])
        poliza_ind = Polizas.objects.get(id = r['id'], document_type__in = [1,11,3,12], org_name = request.GET.get('org'))
        # print('hecho---*',poliza_upd,poliza_ind.id,poliza_ind.poliza_number,r['id'])
        # LOG fin
        try:
            serializer = PolizaInfoSerializer(poliza_ind, context={'request': request}, many = False)                      
            results.append(serializer.data)
        except Exception as error_ser:
            polizaFin = Polizas.objects.get(pk = poliza_ind.id, org_name = request.GET.get('org'))
            serializer = PolizaInfoSerializer(polizaFin, context={'request': request}, many = False)
            results.append(serializer.data)
    return JsonResponse({'data': results})

