@api_view(['POST'])
# @pm((AllowAny, ))
def PolizasByEmaiIris(request,username=None):
    emails = request.data
    queryset = Assign.objects.filter(user__email__in = emails).filter(poliza__document_type__in = [1,12], poliza__status__in = [10,14])
    caratulas = Polizas.objects.filter(document_type__in = [3,11], status__in = [10,14]).values_list('pk', flat = True)
    queryset_certs = Assign.objects.filter(user__email__in = emails).filter(poliza__document_type__in = [6,12], poliza__caratula__in = list(caratulas))

    queryset = queryset | queryset_certs

    if emails:
        queryset_ = Pendients.objects.filter(email__in = emails).filter(poliza__document_type__in = [1,12], poliza__status__in = [10,14])
    else:
        queryset_ = None
    if not queryset.exists() and not queryset_.exists():
        return Response({'error':'No existen polizas vigentes o por iniciar asignadas a ese usuario'})

    polizas = []
    for poliza in queryset:
        if poliza.poliza.status != 0:
            if not poliza.poliza in polizas:
                polizas.append(poliza.poliza)
    
    if queryset_:
        for pol in queryset_:
            if pol.poliza.status != 0:
                if not pol.poliza in polizas:
                    polizas.append(pol.poliza)
    serializer = PolizaListAppSerializer(polizas, context = {'request': request}, many = True)
    return Response(serializer.data)
