from rest_framework.views import APIView
class PolizaAutocompleteView(APIView):
    permission_classes = (IsAuthenticatedV2, PolizasPermissionV2)

    def get(self, request):
        q = (request.GET.get('q') or '').strip()
        if len(q) < 3:
            return Response([])
        limit = request.GET.get('limit') or 20
        org_name = request.GET.get('org')
        try:
            limit = min(int(limit), 20)
        except:
            limit = 20
        types_list = [1,3]
        # Normaliza búsqueda (opcional)
        q_norm = q.replace(' ', '')
        qs = Polizas.objects.filter(org_name=org_name, document_type__in = [1,3], status__in=[10,11,4,14,13,12,15,16]).exclude(status=0)
        # SOLO individuales y grupo (ajusta a tu lógica real)
        pol_types_q = Q()
        qs = qs.filter(pol_types_q)
        # Búsqueda barata primero: prefix
        qs = qs.filter(
            Q(poliza_number__istartswith=q_norm) |
            Q(poliza_number__istartswith=q)
        )
        qs = qs.select_related('aseguradora', 'contractor').only(
            'id', 'poliza_number', 'start_of_validity', 'end_of_validity',
            'aseguradora__alias', 'contractor__full_name'
        ).order_by('-start_of_validity')[:limit]
        out = []
        for p in qs:
            label = u'{0} | {1} - {2} | {3} | {4}'.format(
                p.poliza_number,
                p.start_of_validity.strftime('%d/%m/%Y') if p.start_of_validity else '',
                p.end_of_validity.strftime('%d/%m/%Y') if p.end_of_validity else '',
                getattr(getattr(p, 'aseguradora', None), 'alias', '') or '',
                getattr(getattr(p, 'contractor', None), 'full_name', '') or ''
            )
            out.append({
                'id': p.id,
                'poliza_number': p.poliza_number,
                'validity_start': p.start_of_validity,
                'validity_end': p.end_of_validity,
                'label': label,
            })
        return Response(out)
