from rest_framework import viewsets, status
from rest_framework.decorators import list_route, detail_route
from django.utils import timezone

from rest_framework import status
from rest_framework.response import Response
from rest_framework.parsers import MultiPartParser, FormParser, JSONParser

class CondicionGeneralViewSet(viewsets.ModelViewSet):
    permission_classes = (IsAuthenticatedV2,)
    queryset = CondicionGeneral.objects.all()
    parser_classes = (MultiPartParser, FormParser, JSONParser)  # importante para FileField

    def get_serializer_class(self):
        if self.request.method in ('POST', 'PUT', 'PATCH'):
            return CondicionGeneralWriteSerializer
        return CondicionGeneralSerializer_detalle

    def get_queryset(self):
        org = self.request.GET.get('org')
        qs = CondicionGeneral.objects.filter(org_name=org, deleted_at__isnull=True)

        aseguradora = self.request.GET.get('aseguradora')
        subramo = self.request.GET.get('subramo')
        q = self.request.GET.get('q')
        subramo_id=0
        try:
            if subramo and int(subramo):
                subramo_id = subramo
        except:
            subramo_id=0
        if aseguradora:
            qs = qs.filter(aseguradora__id=aseguradora)
        if subramo:
            if subramo_id:
                qs = qs.filter(subramo__id=subramo)
            else:
                qs = qs.filter(subramo__subramo_name=subramo)
        if q:
            qs = qs.filter(nombre__icontains=q)

        return qs.order_by('-id')

    def perform_create(self, serializer):
        org = self.request.GET.get('org')
        serializer.save(org_name=org)

    def destroy(self, request, *args, **kwargs):
        obj = self.get_object()
        obj.soft_delete()
        return Response(status=status.HTTP_204_NO_CONTENT)
class PolizaCondicionGeneralViewSet(viewsets.ModelViewSet):
    permission_classes = (IsAuthenticatedV2,)
    serializer_class = PolizaCondicionGeneralSerializer

    def get_queryset(self):
        org=self.request.GET.get('org')
        policy_id = self.kwargs['id']
        return PolizaCondicionGeneral.objects.filter(
            policy_id=policy_id,
            policy__org_name=org,
            condicion__deleted_at__isnull=True,
            condicion__activo=True
        ).select_related('condicion')

    def perform_create(self, serializer):
        org=self.request.GET.get('org')
        pol = Polizas.objects.get(id=self.kwargs['id'], org_name=org)
        condicion_id = self.request.data.get('condicion')
        condicion = CondicionGeneral.objects.get(
            id=condicion_id,
            org_name=org,
            deleted_at__isnull=True,
            activo=True
        )

        # (Opcional recomendado) validar que coincida con aseguradora/subramo de la póliza
        if pol.aseguradora_id != condicion.aseguradora.id or pol.subramo.subramo_code != condicion.subramo.subramo_code:
            raise serializers.ValidationError("La condición no corresponde a la aseguradora/subramo de la póliza")

        serializer.save(policy=pol, condicion=condicion)

    
    @list_route(methods=['post'])
    def set(self, request, id=None):
        org = request.GET.get('org')
        policy_id = self.kwargs['id']

        ids = request.data.get('document_ids', None)
        if ids is None:
            ids = request.data.get('condicion', None)
        if ids is None:
            ids = request.data.get('condiciones_generales', None)

        # single int -> list
        if isinstance(ids, int):
            ids = [ids]

        # normaliza + quita falsy + dedupe
        ids = ids or []
        ids = [int(x) for x in ids if x]
        ids = list(set(ids))

        with transaction.atomic():
            # ✅ IMPORTANTE: no filtres por org_name aquí
            # /set/ significa "deja exactamente esta lista"
            PolizaCondicionGeneral.objects.filter(policy_id=policy_id).delete()

            rows = [PolizaCondicionGeneral(policy_id=policy_id, condicion_id=cid) for cid in ids]
            if rows:
                PolizaCondicionGeneral.objects.bulk_create(rows)

        return Response({'ok': True, 'count': len(ids)}, status=status.HTTP_200_OK)
    
class AsignarCondicionesGeneralesPolizaView(APIView):
    permission_classes = (IsAuthenticatedV2,)
    parser_classes = (JSONParser, FormParser, MultiPartParser)

    def post(self, request, *args, **kwargs):
        org = request.GET.get('org')
        if not org:
            return Response({'org': ['org es requerido en querystring']}, status=status.HTTP_400_BAD_REQUEST)

        ser = AsignarCondicionesGeneralesPolizaSerializer(data=request.data)
        ser.is_valid(raise_exception=True)
        data = ser.validated_data

        policy_id = data['policy_id']
        aseguradora_id = data['aseguradora']
        subramo_id = data['subramo']
        replace = data.get('replace', True)

        # 1) Validar póliza existe y pertenece a org
        try:
            pol = Polizas.objects.get(id=policy_id, org_name=org)
        except Polizas.DoesNotExist:
            return Response({'policy_id': ['Póliza no encontrada para org']}, status=status.HTTP_404_NOT_FOUND)

        # 2) Elegir qué condiciones asignar:
        #    - Si mandas document_ids, se usan esas
        #    - Si NO mandas, se asignan TODAS las activas del catálogo por aseguradora+subramo
        doc_ids = data.get('document_ids', None)
        doc_ids = data.get('document_ids')
        if not doc_ids:
            return Response({
                'ok': True,
                'policy_id': pol.id,
                'assigned_count': 0,
                'assigned_ids': [],
                'replace': replace,
                'message': 'No se recibió document_ids o viene vacío, no se asignó ninguna condición general.'
            }, status=status.HTTP_200_OK)
        # Solo asignar si viene document_ids
        if 'document_ids' not in data:
            return Response({
                'ok': True,
                'policy_id': pol.id,
                'assigned_count': 0,
                'assigned_ids': [],
                'replace': replace,
                'message': 'No se recibió document_ids, no se asignó ninguna condición general.'
            }, status=status.HTTP_200_OK)

        doc_ids = data.get('document_ids', [])

        cond_qs = CondicionGeneral.objects.filter(
            id__in=doc_ids,
            org_name=org,
            activo=True,
            deleted_at__isnull=True
        )

        cond_ids = list(cond_qs.values_list('id', flat=True))

        with transaction.atomic():
            if replace:
                PolizaCondicionGeneral.objects.filter(policy_id=pol.id).delete()

            existing = set(
                PolizaCondicionGeneral.objects.filter(
                    policy_id=pol.id,
                    condicion_id__in=cond_ids
                ).values_list('condicion_id', flat=True)
            )

            rows = []
            for cid in cond_ids:
                if cid in existing:
                    continue
                rows.append(
                    PolizaCondicionGeneral(
                        policy_id=pol.id,
                        condicion_id=cid
                    )
                )

            if rows:
                PolizaCondicionGeneral.objects.bulk_create(rows)

        return Response({
            'ok': True,
            'policy_id': pol.id,
            'assigned_count': len(cond_ids),
            'assigned_ids': cond_ids,
            'replace': replace
        }, status=status.HTTP_200_OK)
