class CondicionGeneralUsageView(APIView):
    permission_classes = (IsAuthenticatedV2,)

    def get(self, request, pk):
        org = request.GET.get('org')
        if not org:
            return Response({'org': ['org es requerido']}, status=status.HTTP_400_BAD_REQUEST)
        cnt = PolizaCondicionGeneral.objects.filter(
            condicion_id=pk,
            policy__org_name=org
        ).values('policy_id').distinct().count()
        return Response({'policies_count': cnt}, status=status.HTTP_200_OK)
