from django.http import JsonResponse
from django.views.decorators.csrf import csrf_exempt
import datetime as datetimeModule
import sys

@csrf_exempt
def diagnostic(request):
    """Endpoint de diagnóstico para Django 1.8 / Python 3.5"""
    
    # Obtener headers de manera compatible
    headers = {}
    for key, value in request.META.items():
        if key.startswith('HTTP_'):
            header_name = key[5:].replace('_', '-').title()
            headers[header_name] = value
    
    # Headers específicos
    auth_header = request.META.get('HTTP_AUTHORIZATION', 'NO HAY')
    content_type = request.META.get('CONTENT_TYPE', 'NO HAY')
    
    # EN DJANGO 1.8: is_authenticated es un MÉTODO, no una propiedad
    try:
        # Así se llama en Django 1.8
        is_auth = request.user.is_authenticated()
        user_str = str(request.user) if is_auth else 'Anonymous'
    except:
        # Fallback por si acaso
        try:
            is_auth = request.user.is_authenticated
            user_str = str(request.user) if is_auth else 'Anonymous'
        except:
            is_auth = False
            user_str = 'Error getting user'
    
    # Construir respuesta - asegurando que todo sea serializable
    info = {
        'status': 'ok',
        'server_time': str(datetimeModule.datetime.now()),
        'python_version': sys.version,
        'path': request.path,
        'method': request.method,
        'headers': headers,
        'authorization_header': str(auth_header),  # Asegurar string
        'content_type': str(content_type),
        'user': user_str,
        'authenticated': is_auth,  # Ahora es booleano
        'meta_keys_with_auth': [str(k) for k in request.META.keys() if 'AUTH' in k or 'HEADER' in k],
    }
    
    # Imprimir en consola
    print("\n" + "="*60)
    print("🚨 DIAGNÓSTICO - PETICIÓN RECIBIDA (Django 1.8)")
    print("="*60)
    print("TIME: {}".format(datetimeModule.datetime.now()))
    print("AUTH HEADER: {}".format(auth_header))
    print("USER: {}".format(user_str))
    print("AUTHENTICATED: {}".format(is_auth))
    print("HEADERS RECIBIDOS:")
    for h in sorted(headers.keys()):
        print("  {}: {}".format(h, headers[h]))
    print("="*60)
    print("\n")
    
    return JsonResponse(info)
